import type { Drill } from "./types";

// Sales / senior drills, keyed by module slug — 25 per module.
// Pitched at a sales/marketing executive (VP Sales / CRO / CMO-track): board updates,
// C-suite QBRs, big-deal negotiations, pricing and GTM strategy, org redesigns,
// missed-quarter explanations. Merged into course.ts.
export const SALES_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-sales-senior-01","level":"senior","profession":"sales","title":"The buried board headline","scenario":"You're drafting the revenue section of the quarterly board deck. The headline is that pipeline coverage for next quarter is 3.4x — the strongest in two years — but your draft opens with a recap of the demand-gen reorg that produced it.","task":"Write a 1-2 sentence opening for the revenue section that leads with the headline.","tips":["Sentence one is the number and what it means, not how you got there.","Directors skim: if the coverage figure is in paragraph three, it doesn't exist.","The reorg story is support — one clause at most."],"focus":["structure","impact"],"placeholder":"Pipeline coverage for Q3 is 3.4x — the strongest entry position in two years."},
    {"id":"lead-sales-senior-02","level":"senior","profession":"sales","title":"The miss the CEO hears from you first","scenario":"The quarter closed 8% below plan after two enterprise deals slipped. You're emailing the CEO before finance circulates the flash numbers, and your draft opens with three paragraphs on everything the team executed well.","task":"Write a 2-3 sentence email that states the miss and the cause in the first sentence.","tips":["Lead with the number: 8% below, two named slips.","Padding before bad news reads as spin to a CEO.","End with when they'll get the full picture, not a defense."],"focus":["clarity","impact"],"placeholder":"We closed Q2 at 92% of plan — the Meridian and TelNor deals slipped into July."},
    {"id":"lead-sales-senior-03","level":"senior","profession":"sales","title":"The ask to the customer's CEO","scenario":"An eight-figure renewal has stalled in the customer's procurement for six weeks. You're writing directly to their CEO, whom you've met twice, and your draft warms up with two paragraphs of relationship history before the ask.","task":"Write an email opening (1-2 sentences) that puts the specific ask first.","tips":["A CEO reads the first line and decides whether to keep reading.","Name exactly what you need: 30 minutes, this week, to resolve one open term.","Relationship warmth can live in one clause, not two paragraphs."],"focus":["clarity","audience"]},
    {"id":"lead-sales-senior-04","level":"senior","profession":"sales","title":"The forecast call opener","scenario":"The CEO now joins your Monday forecast call. Your habit is to walk region by region for ten minutes before anyone hears the company number, and last week she interrupted to ask for it.","task":"Write the first two sentences of the call: the company number, then the change since last week.","tips":["Call the number in the first breath: commit, best case, delta.","Region detail is drill-down, not the opening.","If the number moved, say why in one clause."],"focus":["structure","concision"],"placeholder":"Commit is $14.2M, up $600K from last week —"},
    {"id":"lead-sales-senior-05","level":"senior","profession":"sales","title":"The QBR that starts in the weeds","scenario":"You're opening a QBR with a customer's C-suite. The headline is that your platform cut their order-processing cost 22% this year, but your first slide's talk track starts with your company's product roadmap.","task":"Write a 1-2 sentence QBR opening that leads with the value delivered to them.","tips":["Their executives came to hear about their business, not yours.","Lead with the outcome in their metric: 22% cost reduction.","Roadmap belongs at the end, framed as what's next for them."],"focus":["audience","impact"]},
    {"id":"lead-sales-senior-06","level":"senior","profession":"sales","title":"The headcount ask that buries itself","scenario":"You need CFO approval for six enterprise AEs starting next quarter. Your draft memo walks through the capacity model, ramp assumptions, and territory math for a page before the ask appears.","task":"Write an opening line that states the ask and the payback up front.","tips":["Lead with the decision: six AEs, starting Q3, at what cost.","Pair the ask with the return in the same sentence.","The model is the appendix, not the opening argument."],"focus":["clarity","structure"],"placeholder":"I'm asking for six enterprise AEs starting Q3 — $1.8M loaded cost against $7M in incremental year-one pipeline."},
    {"id":"lead-sales-senior-07","level":"senior","profession":"sales","title":"The win announcement","scenario":"Your team just closed the largest deal in company history — $4.2M ARR with a Fortune 100 retailer. Your draft for the company-wide channel opens with the nine-month history of the pursuit.","task":"Write a 1-2 sentence announcement that leads with the logo and the number.","tips":["First line: who, how big, why it matters.","The journey is a great second paragraph, not the headline.","Name the people who closed it — briefly, after the news."],"focus":["impact","concision"],"placeholder":"We just signed the largest deal in company history: $4.2M ARR with"},
    {"id":"lead-sales-senior-08","level":"senior","profession":"sales","title":"The pricing recommendation in paragraph nine","scenario":"You're recommending a 7% list-price increase to the executive team. Your memo spends two pages on methodology, benchmarks, and elasticity analysis before the recommendation appears.","task":"Write the memo's opening sentence: the recommendation, stated plainly.","tips":["State the recommendation before the analysis that supports it.","Executives read the first line to decide how carefully to read the rest.","Include the one number that makes it credible."],"focus":["clarity","structure"]},
    {"id":"lead-sales-senior-09","level":"senior","profession":"sales","title":"The churn flag","scenario":"Your second-largest customer — $1.8M ARR — just signaled they may not renew in six months. Your message to the CEO opens with context about their new CIO and your CSM transition before naming the risk.","task":"Write a 2-3 sentence message that leads with the risk and its size.","tips":["First sentence: the account, the dollars, the probability as you see it.","Context explains the risk; it must not precede it.","Close with what you're doing and what you need from the CEO."],"focus":["clarity","impact"]},
    {"id":"lead-sales-senior-10","level":"senior","profession":"sales","title":"The yes/no the CEO asked","scenario":"The CEO Slacks you: \"Will we hit the Q4 number?\" You believe yes, with one real risk — a $1.2M deal awaiting the customer's board approval. Your instinct is to lay out the whole pipeline before answering.","task":"Write a reply that answers in the first word, then names the one risk.","tips":["\"Yes\" or \"no\" first — the CEO asked a binary question.","One caveat, quantified, is credible; five caveats is a dodge.","Offer the detail as an option, don't force it."],"focus":["concision","clarity"],"placeholder":"Yes — with one watch item:"},
    {"id":"lead-sales-senior-11","level":"senior","profession":"sales","title":"The territory memo that hides the change","scenario":"You're announcing a territory redesign to 200 sellers. What every rep cares about — their account list changes January 1 and mappings arrive next week — sits under four paragraphs about market strategy.","task":"Write an opening 1-2 sentences that lead with what changes for reps and when.","tips":["Lead with the reader's question: what happens to my accounts, and when?","Strategy rationale earns a paragraph — after the facts.","Name the date twice if you must; missing it breeds rumor."],"focus":["audience","clarity"]},
    {"id":"lead-sales-senior-12","level":"senior","profession":"sales","title":"The analyst's differentiation question","scenario":"On an industry-analyst briefing, the analyst asks: \"What actually differentiates you from Coretex?\" Your habit is to start with company history and market context before landing the answer.","task":"Write a spoken answer (2-3 sentences) that names the differentiation in sentence one.","tips":["Answer the question in the first sentence, then support it.","One sharp differentiator beats a list of five.","Analysts quote opening sentences; write yours to be quoted."],"focus":["clarity","impact"]},
    {"id":"lead-sales-senior-13","level":"senior","profession":"sales","title":"The deal-desk exception, due today","scenario":"A $900K deal will sign this week only if the CFO approves non-standard payment terms today. Your draft to her recounts the whole negotiation before stating what you need and by when.","task":"Write a 2-3 sentence request that leads with the ask and the deadline.","tips":["First line: the approval needed, the deadline, the deal size.","Give her the one fact she needs to say yes, not the saga.","Make the default easy: \"reply 'approved' and I'll handle the rest.\""],"focus":["clarity","concision"],"placeholder":"I need your approval by 5pm today on net-90 terms for the Halvorsen deal ($900K) —"},
    {"id":"lead-sales-senior-14","level":"senior","profession":"sales","title":"The partner proposal","scenario":"You're emailing a hyperscaler's channel VP to propose a co-sell motion. Your draft opens with flattery about mutual customers and market alignment; the actual proposal — and what's in it for them — arrives in paragraph four.","task":"Rewrite the opening so the proposal and their upside lead.","tips":["Busy executives forward emails whose first line explains the deal.","Lead with what you're proposing and what they gain, in numbers.","Warmth survives fine in a closing line."],"focus":["structure","audience"]},
    {"id":"lead-sales-senior-15","level":"senior","profession":"sales","title":"The board pre-read nobody finishes","scenario":"Your three-page pipeline pre-read makes one point that matters: mid-market is outperforming, enterprise is stalling, and you're shifting $1.5M of program spend accordingly. That point currently appears on page two.","task":"Write the pre-read's opening 1-2 sentences carrying that conclusion.","tips":["Directors read page one, sentence one, then skim.","The shift in spend is the decision — lead with it.","Signal the structure: \"detail on each follows.\""],"focus":["structure","clarity"]},
    {"id":"lead-sales-senior-16","level":"senior","profession":"sales","title":"The campaign result the CEO should see first","scenario":"Your brand campaign drove a 31% lift in qualified pipeline — the result the CEO bet budget on. Your email update opens with campaign mechanics, channel mix, and creative testing before the number.","task":"Write a 2-sentence update that leads with the result.","tips":["The CEO funded an outcome; report the outcome first.","Mechanics are for the appendix or a follow-up meeting.","Tie the number to the next decision: scale, hold, or stop."],"focus":["impact","concision"],"placeholder":"The campaign delivered: qualified pipeline is up 31% quarter over quarter."},
    {"id":"lead-sales-senior-17","level":"senior","profession":"sales","title":"The kickoff opening line","scenario":"You're writing your sales-kickoff keynote. The year has one priority — multi-product expansion in the installed base — but your draft opens with five minutes of thank-yous and a story from your first sales job.","task":"Write the keynote's first two sentences, leading with the year's single priority.","tips":["A room of 300 sellers remembers one sentence; make it the first one.","Stories work — after the point, in service of it.","If the priority needs a paragraph to state, it isn't one priority."],"focus":["impact","clarity"]},
    {"id":"lead-sales-senior-18","level":"senior","profession":"sales","title":"The save that needs the CEO","scenario":"Your churning $1.8M account will take a call from your CEO — their COO asked for it, and Thursday is the window. Your message to the CEO describes the whole account history before the ask surfaces.","task":"Write a message that leads with the ask: join one call, Thursday, here's why.","tips":["Lead with the action and the time slot.","One sentence of stakes: what the call saves.","Attach the briefing; don't inline it."],"focus":["clarity","concision"]},
    {"id":"lead-sales-senior-19","level":"senior","profession":"sales","title":"The RFP executive summary","scenario":"Your team's 40-page RFP response opens its executive summary with your company's founding story and awards. The evaluation committee's real question is why you win for their specific requirements.","task":"Write an executive-summary opening (1-2 sentences) that leads with why you win for them.","tips":["Name their top requirement and your answer to it, first.","Committees score summaries; boilerplate scores zero.","Every sentence should be about them, not about you."],"focus":["audience","impact"],"placeholder":"You asked for a platform that consolidates three regional systems without downtime —"},
    {"id":"lead-sales-senior-20","level":"senior","profession":"sales","title":"The comp change, stated plainly","scenario":"You're telling frontline sales managers that accelerators now start at 100% of quota instead of 90%. Your draft opens with two paragraphs of compensation philosophy before the change appears.","task":"Write an opening 1-2 sentences that state the change and its effective date first.","tips":["Managers will be asked \"what changed?\" within the hour — arm them in line one.","Philosophy after facts, and briefly.","Say plainly who is affected and who isn't."],"focus":["clarity","precision"],"placeholder":"Starting February 1, accelerators kick in at 100% of quota, not 90%."},
    {"id":"lead-sales-senior-21","level":"senior","profession":"sales","title":"The loss debrief verdict","scenario":"You lost the marquee competitive deal to the incumbent, and the deciding factor was a three-year price lock you couldn't match. Your note to the executive team eases in with process observations before the verdict.","task":"Write a 2-sentence debrief opening: the verdict and the one deciding reason.","tips":["State the loss and the reason in sentence one — no wind-up.","One deciding factor, clearly named, beats six contributing ones.","End with the decision this loss should trigger."],"focus":["clarity","impact"]},
    {"id":"lead-sales-senior-22","level":"senior","profession":"sales","title":"The biggest-risk answer","scenario":"In the pipeline review, the CEO asks: \"What's the single biggest risk to the quarter?\" You start mentally walking through each region's puts and takes. The honest answer is one deal: the $2.1M Averline expansion.","task":"Write a one-sentence spoken answer that names the risk first, with its size.","tips":["One question, one risk, one sentence.","Quantify it: name and dollar figure.","You can offer the region tour after — if asked."],"focus":["concision","precision"],"placeholder":"The Averline expansion — $2.1M, and their CFO hasn't re-engaged since the reorg."},
    {"id":"lead-sales-senior-23","level":"senior","profession":"sales","title":"The budget shift memo","scenario":"You're recommending moving $2M from field events to digital demand-gen based on two quarters of pipeline-per-dollar data. Your memo currently opens with a history of the events program.","task":"Write the memo's first sentence: the recommendation with the supporting number.","tips":["Recommendation first, evidence attached to it in the same breath.","\"Move $2M from X to Y because Z\" is a complete opening.","History is context — it goes below the fold."],"focus":["structure","impact"]},
    {"id":"lead-sales-senior-24","level":"senior","profession":"sales","title":"The escalation heads-up","scenario":"A major customer's CIO just told your account team he's escalating a failed integration directly to your CEO, probably today. Your heads-up to the CEO drafts the whole project history before saying what's coming.","task":"Write a 2-3 sentence heads-up that leads with what's coming and what you need from the CEO.","tips":["First sentence: who is calling, about what, how soon.","Give the CEO the one-line position to hold.","Full history goes in an attached brief, not the message."],"focus":["clarity","structure"],"placeholder":"Heads-up: Dataxion's CIO is escalating the integration failure to you, likely today."},
    {"id":"lead-sales-senior-25","level":"senior","profession":"sales","title":"The milestone you almost buried","scenario":"Net revenue retention crossed 115% for the first time in company history. Your board-update paragraph opens with a methodology note about how NRR is calculated before mentioning the milestone.","task":"Write the paragraph's opening sentence, leading with the milestone.","tips":["Good news deserves the same BLUF discipline as bad news.","Methodology is a footnote — literally.","Say why the milestone matters in one clause: what it signals."],"focus":["impact","concision"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-sales-senior-01","level":"senior","profession":"sales","title":"Forecast confidence for the CFO","scenario":"You're explaining forecast confidence to the CFO ahead of the board meeting. Your draft leans on sales machinery — stage definitions, MEDDPICC scores, weighted pipeline. She thinks in ranges, variance, and what she can commit to the board.","task":"Rewrite the explanation in 2-3 sentences using her language: the number, the range, and what drives the variance.","tips":["Translate methodology into a confidence interval she can defend.","Name the two or three swing deals as the source of variance.","Drop the acronyms — they signal process, not confidence."],"focus":["audience","precision"],"placeholder":"Commit is $14.2M with realistic upside to $15.1M; the swing is three deals —"},
    {"id":"audience-sales-senior-02","level":"senior","profession":"sales","title":"Win rate for the product-minded director","scenario":"A board director with a product background asks why win rate dropped six points. Your instinctive answer is full of sales-ops vocabulary — sales-accepted leads, stage-gate criteria, qualification hygiene — that means nothing to him.","task":"Write a 2-3 sentence answer in plain business terms he can reason about.","tips":["Say what changed in the market or the funnel, not in your CRM fields.","One concrete example lands better than a taxonomy.","He wants a cause he can pressure-test, not a process tour."],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-03","level":"senior","profession":"sales","title":"Pipeline for the engineering all-hands","scenario":"You're giving the revenue update at the company all-hands. Half the room is engineers. \"3.1x coverage and 28% win rate\" is meaningless to them; what they care about is whether the company is healthy and what it means for their roadmap and headcount.","task":"Write a 2-3 sentence update translated into what the numbers mean for the company.","tips":["Convert coverage into plain stakes: are we on track, and what does it fund?","One number, explained, beats four numbers recited.","Connect revenue health to something they own — hiring, roadmap, runway."],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-04","level":"senior","profession":"sales","title":"The value prop for their CFO","scenario":"Your team's proposal for a $2M deal leads with platform capabilities and integration architecture. The economic buyer is the customer's CFO, who will read one page and cares about payback period, risk, and what happens if it fails.","task":"Rewrite the proposal's opening 2-3 sentences for the CFO.","tips":["Lead with payback: dollars saved or earned, by when.","Address risk before she asks: implementation time, switching cost, exit terms.","Features are evidence for claims — not the claims themselves."],"focus":["audience","impact"],"placeholder":"This investment pays back in 14 months: $3.1M in annual processing cost against"},
    {"id":"audience-sales-senior-05","level":"senior","profession":"sales","title":"The ICP without the shorthand","scenario":"You're addressing a class of new-hire AEs on day two. Your usual description of the ideal customer profile is compressed insider shorthand — \"mid-market ops-heavy logos with legacy ERP pain\" — that took you years to load with meaning.","task":"Write a 2-3 sentence description of the ideal customer a brand-new AE can actually use.","tips":["Unpack every compressed term: what does \"ops-heavy\" look like on a call?","Give one recognizable signal they can spot in the first meeting.","Test: could they repeat it accurately to a prospect?"],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-06","level":"senior","profession":"sales","title":"The press quote","scenario":"A business journalist asks where your market is heading. Your first draft answer is dense with insider language — \"consolidation of point solutions into platform plays across the mid-market.\" Her readers are general business readers.","task":"Write a one-sentence quote a non-specialist reader understands and an editor keeps.","tips":["One idea, concrete words, no category jargon.","Say it the way you'd tell a smart friend outside the industry.","If it needs a second sentence to explain, rewrite the first."],"focus":["audience","concision"]},
    {"id":"audience-sales-senior-07","level":"senior","profession":"sales","title":"Procurement is not the champion","scenario":"You've been forwarding your value narrative — transformation, partnership, vision — to the customer's procurement lead. Procurement cares about total cost, contractual risk, and benchmark comparisons. The deal is stalling on their desk.","task":"Write a 2-3 sentence email to procurement in their frame: cost, risk, and comparables.","tips":["Match their scorecard: they're graded on cost and risk, not vision.","Give them ammunition: a benchmark or reference they can cite internally.","Save the transformation story for the sponsor who buys it."],"focus":["audience","precision"]},
    {"id":"audience-sales-senior-08","level":"senior","profession":"sales","title":"The CEO's altitude","scenario":"You sent the CEO a 14-line update on the Averline deal: meeting notes, stakeholder map changes, legal's redline status. He replied \"?\". What he needed: will it close this quarter, and does he need to do anything.","task":"Rewrite the update in 2 sentences at CEO altitude.","tips":["Two questions matter at that altitude: outcome and ask.","Every detail must earn its place by changing his picture.","If there's no ask, say \"nothing needed from you\" — it's information."],"focus":["audience","concision"],"placeholder":"Averline closes this quarter with 80% confidence; nothing needed from you unless"},
    {"id":"audience-sales-senior-09","level":"senior","profession":"sales","title":"Urgency for the legal team","scenario":"Your legal counterpart is treating the Halvorsen redlines as routine — two-week turnaround. The deal dies if paper isn't done in five days. Your draft nudges them with sales pressure: \"this is a must-win, quarter hinges on it.\"","task":"Rewrite the request (2-3 sentences) in terms legal weighs: what's needed, by when, and what's genuinely at risk.","tips":["Legal triages by consequence and deadline, not by sales adrenaline.","Name the specific clauses in play so they can size the work.","Offer a trade: what you'll deprioritize or pre-clear to help."],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-10","level":"senior","profession":"sales","title":"Comp design for the HR review","scenario":"You're proposing steeper accelerators to the head of HR, and your draft argues in sales math — attainment curves, OTE leverage, quota coverage. HR evaluates comp changes on retention, fairness, and internal-equity risk.","task":"Write 2-3 sentences making the case in HR's terms.","tips":["Lead with retention: what top-performer attrition costs and how this helps.","Address fairness explicitly — who could see this as inequitable?","Keep one sales number, translated into a people outcome."],"focus":["audience","structure"]},
    {"id":"audience-sales-senior-11","level":"senior","profession":"sales","title":"Loss data the product team can use","scenario":"You want product to prioritize API rate limits, and your draft says \"we're getting killed in enterprise deals on API limits.\" Product hears sales noise. They act on specifics: which customers, what use case, what revenue.","task":"Write a 2-3 sentence message that turns the complaint into evidence product can rank.","tips":["Name deals and dollars: three losses, $X ARR, same objection verbatim.","Describe the customer's use case, not your frustration.","End with a specific, sized ask — not \"fix the API.\""],"focus":["audience","precision"],"placeholder":"We've lost three enterprise deals this quarter — $2.7M combined — to the same objection:"},
    {"id":"audience-sales-senior-12","level":"senior","profession":"sales","title":"Champion mail vs. buyer mail","scenario":"You drafted one email and plan to send it to both your champion (a director who loves the product) and the economic buyer (a COO you've met once). The COO version is the one that matters, and she cares about operational risk and outcomes, not features.","task":"Write the 2-3 sentence version for the COO.","tips":["Pick one primary audience per message — the COO, here.","Lead with the operational outcome she owns.","Let the champion carry the feature enthusiasm internally."],"focus":["audience","impact"]},
    {"id":"audience-sales-senior-13","level":"senior","profession":"sales","title":"GTM for public investors","scenario":"You're drafting your investor-day segment on go-to-market. Your outline is written in operator dialect — PLG motion, SDR-sourced pipeline, land-and-expand. Public investors need the economics: how you acquire customers, what it costs, why it scales.","task":"Rewrite your opening 2-3 sentences for an investor audience.","tips":["Translate motion names into economics: cost to acquire, time to payback.","Investors pattern-match to models they know — give them the anchor.","One internal term explained is fine; five unexplained is a fog."],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-14","level":"senior","profession":"sales","title":"Enablement the partner reps will read","scenario":"You're writing the launch note for a reseller partner's sales force. Your draft explains your org structure and product strategy. Partner reps skim for exactly two things: how to pitch it in one line, and what they earn on it.","task":"Write a 2-3 sentence enablement opening that gives them both.","tips":["Their attention is rented — pay for it in the first line with the margin.","One pitch sentence they can say verbatim to a customer.","Your org chart is irrelevant to someone else's seller."],"focus":["audience","concision"]},
    {"id":"audience-sales-senior-15","level":"senior","profession":"sales","title":"NRR for the director who won't ask twice","scenario":"After the board meeting, a director without a SaaS background quietly asks what net revenue retention actually means. He risked looking uninformed to ask; a textbook definition or condescension both fail here.","task":"Write a 1-2 sentence explanation with a concrete example and why it matters.","tips":["Use dollars, not a formula: \"customers who paid us $100 last year pay us $115 now.\"","Attach the so-what: growth without new logos.","Respect the question — no preamble about how it's commonly misunderstood."],"focus":["audience","clarity"],"placeholder":"It means the customers we already had a year ago now pay us 15% more —"},
    {"id":"audience-sales-senior-16","level":"senior","profession":"sales","title":"The miss, explained to everyone","scenario":"You're explaining the missed quarter at the company all-hands. Employees aren't parsing pipeline mechanics; they want to know three things: how bad is it, are jobs safe, and what changes now.","task":"Write a 3-4 sentence all-hands explanation that answers their real questions.","tips":["Answer the unasked question — stability — directly and honestly.","One cause, plainly stated, beats a funnel autopsy.","Say what changes and what doesn't; specifics calm rooms."],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-17","level":"senior","profession":"sales","title":"Attribution for the skeptical sales managers","scenario":"You run marketing and your MQL report lands flat with sales managers who think marketing leads are junk. Your draft defends the attribution model. What they actually care about: meetings on their reps' calendars and pipeline they can close.","task":"Rewrite the update (2-3 sentences) in their currency: meetings, pipeline, closed-won.","tips":["Report the metric they're paid on, not the one you're paid on.","One named win sourced from a campaign converts more skeptics than a model.","Invite the audit — confidence reads as credibility."],"focus":["audience","impact"]},
    {"id":"audience-sales-senior-18","level":"senior","profession":"sales","title":"A paragraph for their board","scenario":"Your champion — a VP at your biggest customer — asks for one paragraph she can paste into her own board materials describing the partnership's results. It must read like her board's language, not your marketing.","task":"Write that paragraph (3-4 sentences) in the customer's voice, with their outcomes.","tips":["Write as her, about her company's results — you are a supporting noun.","Use their board's metrics: cost, throughput, risk reduced.","Strip every trace of vendor promotion; it embarrasses her if it survives."],"focus":["audience","precision"]},
    {"id":"audience-sales-senior-19","level":"senior","profession":"sales","title":"Selling past the CTO's defenses","scenario":"You're emailing a prospect's CTO who has been burned by vendor promises before. Your draft is ROI language and customer logos. What a CTO weighs: architecture fit, failure modes, what breaks at scale, and who fixes it.","task":"Write a 2-3 sentence email opening addressed to those concerns.","tips":["Lead with the technical question he's actually asking, and answer it.","Offer proof he can verify: reference architecture, an engineer-to-engineer call.","ROI language to a CTO reads as someone else's email forwarded."],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-20","level":"senior","profession":"sales","title":"The 30-second renewal read","scenario":"The renewal notice for a $600K account will get 30 seconds from their COO, who barely knows your product exists. Your draft opens with contract mechanics. Her question is: what did this thing do for us?","task":"Write a 2-sentence opening that front-loads their realized value in her KPIs.","tips":["Lead with their number: hours saved, cost avoided, volume handled.","Make the first sentence survive being the only sentence read.","Contract logistics go last, in one line."],"focus":["audience","impact"],"placeholder":"In the past 12 months your team processed 2.1M orders through our platform — saving roughly"},
    {"id":"audience-sales-senior-21","level":"senior","profession":"sales","title":"Same news, analyst version","scenario":"You're announcing a shift from seat-based to usage-based pricing. The press release is written. Now you're briefing an industry analyst, who doesn't want the announcement — she wants the market logic: why now, what it signals, who follows.","task":"Write 2-3 sentences for the analyst briefing framed as market reasoning.","tips":["Analysts trade in patterns — position the move inside one.","Admit the trade-off; analysts distrust announcements without costs.","Give her a sentence she can put in a research note."],"focus":["audience","structure"]},
    {"id":"audience-sales-senior-22","level":"senior","profession":"sales","title":"One announcement, one primary audience","scenario":"A routing change mostly affects your 40 field sellers; the 120 inside-sales reps are barely touched. Your draft addresses \"the whole revenue org\" evenly, so field sellers can't tell how much it hits them.","task":"Rewrite the opening 2-3 sentences addressed squarely to field sellers, with one line scoping everyone else out.","tips":["Pick the primary audience and write to them by name.","Tell the unaffected majority early that they can stop reading.","Evenly-addressed messages serve no one fully."],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-23","level":"senior","profession":"sales","title":"Ninety seconds at the CEO's staff meeting","scenario":"You have 90 seconds to update the CEO's staff — heads of product, engineering, finance — on pipeline. Reciting sales metrics wastes the slot. Each peer cares about one thing: what your number means for their resourcing and plans.","task":"Write the 90-second update (3-4 sentences) pitched at cross-functional altitude.","tips":["Lead with the one conclusion that affects their world.","Convert pipeline into implications: hiring pace, capacity needs, spend timing.","Leave the funnel detail for your own staff meeting."],"focus":["audience","concision"]},
    {"id":"audience-sales-senior-24","level":"senior","profession":"sales","title":"The kickoff note for their ops team","scenario":"You won the deal with a strategic vision that convinced their C-suite. Now you're writing the kickoff note to the customer's operations team — the people whose daily work changes. Vision language will read as noise to them.","task":"Write a 2-3 sentence kickoff opening for the ops team: what changes for them, when, and who helps.","tips":["The audience changed, so the message must: outcomes → logistics.","Answer their real questions: what's different Monday, and who do I call?","Respect their expertise — they run the process you're changing."],"focus":["audience","clarity"]},
    {"id":"audience-sales-senior-25","level":"senior","profession":"sales","title":"Closing the VP candidate","scenario":"You're trying to close a strong VP-of-sales candidate who has two other offers. Your draft note is company boilerplate — mission, culture, momentum. Candidates at that level decide on territory quality, comp mechanics, and why this window matters.","task":"Write a 2-3 sentence note pitched at what she's actually weighing.","tips":["Name the specifics she can't get from the careers page: patch, pipeline, comp structure.","Answer \"why now\" with a concrete company-stage argument.","Boilerplate signals you'd manage her with boilerplate too."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-sales-senior-01","level":"senior","profession":"sales","title":"The QBR that needs a spine","scenario":"Your customer QBR deck is 24 slides of everything that happened: tickets, releases, meetings, adoption charts. The customer's C-suite has 30 minutes. Right now there's no through-line — just a chronological dump.","task":"Write a governing statement plus three supporting buckets that organize the whole QBR.","tips":["One governing idea on top: what this year means for their business.","Three buckets, not nine — value delivered, what's at risk, what's next.","Every slide should map to one bucket or get cut."],"focus":["structure","clarity"],"placeholder":"This year we moved you from firefighting to scale. Three things made that true:"},
    {"id":"structure-sales-senior-02","level":"senior","profession":"sales","title":"SCQA for the pricing memo","scenario":"You're recommending a move to usage-based pricing to the executive team. Your draft jumps straight to the new model. It lands better if you set up the situation, the tension, and the question the model answers.","task":"Write a 4-sentence SCQA opening (situation, complication, question, answer) for the memo.","tips":["Situation: the shared, uncontested fact about today's pricing.","Complication: what changed that makes it a problem now.","Question then answer: pose the decision, then state your recommendation."],"focus":["structure","clarity"]},
    {"id":"structure-sales-senior-03","level":"senior","profession":"sales","title":"PREP under the CEO's question","scenario":"In the pipeline review, the CEO asks whether you should pull demand-gen spend forward into Q3. You know the answer is yes but tend to ramble through considerations before landing.","task":"Write a spoken PREP answer (point, reason, example, point) in 4-5 sentences.","tips":["Point first: yes, pull it forward.","One reason, one concrete example — not a survey of factors.","Return to the point to close cleanly."],"focus":["structure","concision"],"placeholder":"Yes, pull it forward. The reason is timing:"},
    {"id":"structure-sales-senior-04","level":"senior","profession":"sales","title":"Grouping the messy risk list","scenario":"Your board slide lists 11 risks to the number in the order they occurred to you: a slipped deal, a comp complaint, a competitor's launch, an open VP seat, a churning logo, and more. Directors can't hold 11 items.","task":"Regroup the 11 into three named categories with a one-line header each.","tips":["Find the three buckets: pipeline, people, market — or whatever fits.","Name each bucket so a director remembers the shape, not the items.","Order buckets by what threatens the number most."],"focus":["structure","clarity"]},
    {"id":"structure-sales-senior-05","level":"senior","profession":"sales","title":"The board narrative arc","scenario":"Your revenue board section is a pile of metrics with no argument. The real story is: we beat plan, but the mix shifted risky, so we're reallocating. The numbers should serve that arc, not replace it.","task":"Write the three-beat spine (win, but, so) that the metrics hang from.","tips":["Beat one: the headline result.","Beat two: the 'but' that complicates it honestly.","Beat three: the 'so' — the decision it drives."],"focus":["structure","impact"]},
    {"id":"structure-sales-senior-06","level":"senior","profession":"sales","title":"One idea per QBR section","scenario":"A QBR slide titled \"Account Health\" actually carries four ideas: adoption is up, one integration is fragile, their renewal is at risk, and there's an upsell opening. Readers can't tell which is the point.","task":"Split it into a clear governing point plus the supporting sub-points, stated in order.","tips":["Decide the one governing idea the slide exists to make.","Demote the other three to evidence or next steps.","If two ideas truly co-equal, they need two slides."],"focus":["structure","clarity"]},
    {"id":"structure-sales-senior-07","level":"senior","profession":"sales","title":"Sequencing the negotiation ask","scenario":"You're heading into a renewal negotiation with the customer's CFO and have five things to raise: price, term length, an SLA change, a co-marketing clause, and a payment schedule. Raising them in a random order weakens your position.","task":"Write the order you'll raise them in, with a one-line rationale for the sequence.","tips":["Lead with what anchors the whole deal — usually price or term.","Bundle trades so a concession on one buys agreement on another.","Save the smallest asks for when momentum is on your side."],"focus":["structure","impact"]},
    {"id":"structure-sales-senior-08","level":"senior","profession":"sales","title":"The GTM strategy on one page","scenario":"Your go-to-market recommendation for the executive team sprawls across ten pages. The core is three moves: shift upmarket, add a partner motion, and consolidate the SDR org. It's buried in supporting detail.","task":"Write a one-page structure: the governing recommendation and the three moves as headers.","tips":["Governing line: the strategic bet in one sentence.","Three moves as parallel headers a reader can scan in ten seconds.","Detail lives under each header, not above it."],"focus":["structure","concision"]},
    {"id":"structure-sales-senior-09","level":"senior","profession":"sales","title":"The forecast walk that carries","scenario":"Your Monday forecast update wanders region by region with no frame. It would land if it followed one structure every week: company number, biggest movers, biggest risks, the ask.","task":"Write the four-part skeleton with one sentence under each heading for this week.","tips":["Same four headings every week trains the room to follow.","Movers and risks are the story; the regional table is backup.","End with a specific ask or 'no ask this week.'"],"focus":["structure","clarity"],"placeholder":"Number: commit $14.2M. Movers: two deals up, one slipped. Risks:"},
    {"id":"structure-sales-senior-10","level":"senior","profession":"sales","title":"The kickoff keynote outline","scenario":"Your sales-kickoff keynote draft is a stream of themes. You want the room to walk out remembering the shape of the year, which is really: where we won, where we lost, and the one thing we change.","task":"Write a three-part keynote outline with a memorable header for each part.","tips":["Three acts a seller can recite in the hallway afterward.","The third act is the priority — build the first two toward it.","Headers should be verbs or bets, not topics."],"focus":["structure","impact"]},
    {"id":"structure-sales-senior-11","level":"senior","profession":"sales","title":"The missed-quarter memo spine","scenario":"You're writing the missed-quarter memo to the executive team. Your draft mixes causes, defenses, and plans in no order. It needs a spine: what happened, why, and what changes.","task":"Write the memo's three-section spine with a one-sentence header for each.","tips":["Section one states the result plainly — no cushioning.","Section two isolates the root cause, not a list of contributors.","Section three is the forward plan — the only part that earns a defense."],"focus":["structure","clarity"]},
    {"id":"structure-sales-senior-12","level":"senior","profession":"sales","title":"The proposal that answers in order","scenario":"The customer's evaluation committee gave you three explicit criteria: consolidation, uptime, and price. Your proposal addresses them scattered across 40 pages in a different order than they asked.","task":"Write the executive summary's structure so it answers their three criteria in their order.","tips":["Mirror the buyer's structure — it signals you listened.","One crisp paragraph per criterion, headed by the criterion.","Their scoring rubric is your outline; use it."],"focus":["structure","audience"]},
    {"id":"structure-sales-senior-13","level":"senior","profession":"sales","title":"The pyramid for headcount","scenario":"Your ask for six AEs is supported by a dozen data points — ramp curves, coverage gaps, win-rate math, competitor hiring. Thrown at the CFO flat, they don't build to anything.","task":"Structure the argument as one conclusion supported by three grouped reasons.","tips":["Conclusion at the apex: hire six AEs now.","Three reason-groups beneath: capacity, timing, return.","Each data point supports one reason — nothing floats free."],"focus":["structure","precision"]},
    {"id":"structure-sales-senior-14","level":"senior","profession":"sales","title":"The territory-change explainer","scenario":"Your territory-redesign note tries to explain the new model, the rationale, the timeline, and the exceptions all at once, and reps come out confused. It needs clear sections in a logical order.","task":"Write the note's section headers in the order a rep needs them.","tips":["Order by the reader's questions: what changes, when, why, what if I'm an exception.","One question per section, headed as a question if it helps.","Put 'what changes for you' first, philosophy last."],"focus":["structure","audience"]},
    {"id":"structure-sales-senior-15","level":"senior","profession":"sales","title":"The analyst briefing arc","scenario":"You're briefing an industry analyst on your market position. Your draft is a features tour. Analysts follow an arc: where the market is, where you sit, and where you're betting it goes.","task":"Write the three-beat arc as spoken opening lines for the briefing.","tips":["Start with the market movement, not your product.","Place your company inside that movement — the 'where we sit' beat.","End on your bet; analysts write down the bet."],"focus":["structure","audience"]},
    {"id":"structure-sales-senior-16","level":"senior","profession":"sales","title":"The deal-review one-pager","scenario":"Your big-deal review doc for the executive sponsor is a wall of context. It would carry as a one-pager with four fixed sections: the deal, the plan to win, the risks, the ask.","task":"Write the four section headers with a one-line summary under each for this deal.","tips":["Fixed sections make every deal review comparable at a glance.","'Plan to win' is the spine — risks and ask hang off it.","Keep each summary to one sentence; detail lives in the appendix."],"focus":["structure","concision"]},
    {"id":"structure-sales-senior-17","level":"senior","profession":"sales","title":"The board question, structured live","scenario":"A director asks, mid-meeting: \"Why is enterprise stalling while mid-market booms?\" You have three real reasons but tend to blur them into one long answer.","task":"Write a spoken answer that flags 'three reasons' and delivers them as a clean list.","tips":["Signpost the count first: 'Three reasons.'","Deliver them in parallel form so the director can track them.","Rank them — say which matters most and why."],"focus":["structure","clarity"],"placeholder":"Three reasons, in order of weight. First,"},
    {"id":"structure-sales-senior-18","level":"senior","profession":"sales","title":"The pipeline story, not the pipeline table","scenario":"Your board pipeline slide is a stage-by-stage table. It carries no argument. The story is: coverage is healthy, but concentrated in three deals, so the quarter is binary.","task":"Write the SCQA that turns the table into an argument.","tips":["Situation: coverage looks healthy at 3.4x.","Complication: it's concentrated in three deals.","Question and answer: is the quarter safe? Only if two of three land."],"focus":["structure","impact"]},
    {"id":"structure-sales-senior-19","level":"senior","profession":"sales","title":"The enablement doc that scans","scenario":"Your new-product enablement doc for the field is 12 dense paragraphs. Reps need it structured: the pitch, the buyer, the objections, the proof — scannable in two minutes.","task":"Write the four scannable section headers with one line each.","tips":["Reps scan under pressure — headers must answer 'what do I say?'","Objections and proof are what they actually reach for; make them findable.","Lead with the one-line pitch they can memorize."],"focus":["structure","audience"]},
    {"id":"structure-sales-senior-20","level":"senior","profession":"sales","title":"The reorg rationale in three moves","scenario":"You're announcing a revenue-org redesign. Your draft explains it as a list of role changes. It lands as strategy if framed as: the problem today, the new shape, the outcome expected.","task":"Write the three-beat structure for the reorg announcement.","tips":["Name the problem the reorg solves before the boxes move.","Describe the new shape in one clear picture.","End with the measurable outcome you expect — that's the point."],"focus":["structure","clarity"]},
    {"id":"structure-sales-senior-21","level":"senior","profession":"sales","title":"The investor-day GTM segment","scenario":"Your investor-day go-to-market segment is a grab-bag of metrics. Investors need one governing claim — the model is efficient and scaling — with the metrics grouped as proof.","task":"Write the governing claim plus three proof buckets it rests on.","tips":["Governing claim in one sentence investors can quote.","Three buckets: efficiency, durability, expansion — pick what fits.","Assign every metric to a bucket; loose metrics read as noise."],"focus":["structure","precision"]},
    {"id":"structure-sales-senior-22","level":"senior","profession":"sales","title":"The customer escalation summary","scenario":"You're summarizing a customer escalation for the CEO before he takes their call. Your draft is a timeline of emails. He needs it structured: what they want, where we are, what we recommend.","task":"Write the three-part structure with one line under each for this escalation.","tips":["Lead with what the customer wants — that's his first question.","State our current position plainly, no spin.","End with the recommended stance he should take on the call."],"focus":["structure","clarity"],"placeholder":"What they want: a firm fix date and credit. Where we are:"},
    {"id":"structure-sales-senior-23","level":"senior","profession":"sales","title":"The win/loss readout","scenario":"Your quarterly win/loss readout to the exec team is anecdote after anecdote. It would carry if organized around the two or three patterns that actually explain the quarter's results.","task":"Write the governing insight plus the two or three patterns it groups under.","tips":["Lead with the one insight, not the first anecdote.","Group deals into two or three named patterns; anecdotes are evidence.","Each pattern should imply an action — otherwise it's trivia."],"focus":["structure","impact"]},
    {"id":"structure-sales-senior-24","level":"senior","profession":"sales","title":"The comp-plan rollout deck","scenario":"Your new comp-plan rollout deck for managers jumps between mechanics, rationale, and FAQs. Managers need it in a fixed order: what changed, why, what to tell reps, what to escalate.","task":"Write the four-section order with a one-line purpose for each.","tips":["Order by what a manager does next: understand, explain, handle.","'What to tell reps' is the operational core — make it prominent.","End with the escalation path so managers don't improvise."],"focus":["structure","audience"]},
    {"id":"structure-sales-senior-25","level":"senior","profession":"sales","title":"The strategy update, one governing idea","scenario":"Your GTM strategy update to the board spans partnerships, pricing, expansion, and hiring with no unifying idea. It reads as four separate updates rather than one strategy.","task":"Write the single governing idea plus how each of the four threads serves it.","tips":["Find the one bet all four threads support, and state it first.","Show each thread as evidence of the bet, not a standalone item.","If a thread doesn't serve the bet, it belongs in a different memo."],"focus":["structure","clarity"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-sales-senior-01","level":"senior","profession":"sales","title":"The board update that won't stop","scenario":"Your revenue board update runs 220 words to make one point: pipeline is strong but concentrated. It's padded with hedges, throat-clearing, and 'as you know' asides that directors skip anyway.","task":"Cut it to under 60 words while keeping the point and the number.","tips":["Delete every 'as you know' and 'it's worth noting' — directors know.","One number stays; the adjectives around it go.","If a sentence doesn't change the reader's picture, cut it."],"focus":["concision","clarity"]},
    {"id":"concise-sales-senior-02","level":"senior","profession":"sales","title":"The nominalized recommendation","scenario":"Your pricing memo reads: \"The implementation of a revision to our pricing structure would enable the realization of margin improvement.\" Buried in noun-piles is a simple recommendation.","task":"Rewrite it as one direct sentence with verbs, not nominalizations.","tips":["'Implementation of a revision' is just 'revise.'","Turn nouns back into verbs: raise, cut, move.","Say who does what, not that a doing occurs."],"focus":["concision","clarity"],"placeholder":"Raising list prices 7% adds roughly 3 points of margin."},
    {"id":"concise-sales-senior-03","level":"senior","profession":"sales","title":"The hedged forecast","scenario":"Your forecast note says: \"We believe there's a reasonably good chance we may potentially be in a position to possibly hit the number.\" The CEO can't tell what you actually think.","task":"Rewrite it as one confident sentence with a real probability.","tips":["Stack no more than one qualifier — 'likely,' or a percentage.","Hedges multiply doubt; a number bounds it.","If you mean 70%, say 70%."],"focus":["concision","precision"],"placeholder":"We hit the number with about 75% confidence — one deal is the swing."},
    {"id":"concise-sales-senior-04","level":"senior","profession":"sales","title":"The redundant deal email","scenario":"Your note to the customer's CFO is full of doublets: \"first and foremost,\" \"each and every,\" \"full and complete,\" \"in order to.\" It doubles the length and halves the authority.","task":"Rewrite the message stripping every redundant pair, keeping it under 50 words.","tips":["Pick one word from each doublet; the other is dead weight.","'In order to' is 'to.' 'At this point in time' is 'now.'","Executives read tight prose as decisive."],"focus":["concision","clarity"]},
    {"id":"concise-sales-senior-05","level":"senior","profession":"sales","title":"The Slack that buries the ask","scenario":"You Slack the CEO 90 words about the Averline deal, and the actual ask — 'can you email their CFO today' — is in the last line, wrapped in apology.","task":"Rewrite it as two lines: the ask first, one line of context.","tips":["Lead with the verb the CEO needs to do.","One line of context is enough — he'll ask if he needs more.","Cut the apology; the ask is legitimate."],"focus":["concision","impact"],"placeholder":"Can you email Averline's CFO today? Their board approves Friday and one nudge from you"},
    {"id":"concise-sales-senior-06","level":"senior","profession":"sales","title":"The meta-commentary QBR slide","scenario":"Your QBR talk track opens: \"What I want to do now is walk you through what I think is a really important slide about how we've been thinking about your adoption journey.\" All frame, no content.","task":"Cut the meta-commentary and write the one sentence that is the point.","tips":["Delete 'what I want to do is' — just do it.","Naming the slide as important wastes the moment that would prove it.","Start with the finding, not the intent to share a finding."],"focus":["concision","impact"]},
    {"id":"concise-sales-senior-07","level":"senior","profession":"sales","title":"Halving the missed-quarter memo","scenario":"Your missed-quarter memo to the exec team is two pages. The signal — one cause, one fix — is a paragraph. The rest is context, defense, and cushioning that dilutes the accountability.","task":"Cut it to one tight paragraph: cause, impact, fix.","tips":["Defense is the first thing to cut; it reads as spin at length.","Keep the one cause and the one fix; drop the contributing factors.","Shorter reads as more accountable, not less."],"focus":["concision","clarity"]},
    {"id":"concise-sales-senior-08","level":"senior","profession":"sales","title":"The filler-laden voicemail","scenario":"You're leaving a voicemail for a customer executive and your script rambles for 45 seconds before the reason for the call. Executives delete voicemails at the first sign of a wind-up.","task":"Write a 15-second voicemail: who, why, and the one ask.","tips":["Name yourself and the reason in the first breath.","One ask, one callback path — nothing else.","If it can't be said in 15 seconds, send it in writing."],"focus":["concision","impact"]},
    {"id":"concise-sales-senior-09","level":"senior","profession":"sales","title":"The over-qualified 'yes'","scenario":"The CEO asks if the reorg is on track. Your reply: \"Broadly speaking, from what I can tell at this stage, things seem to be more or less proceeding largely as planned.\" Six hedges to say yes.","task":"Rewrite it as a clear answer with at most one honest caveat.","tips":["Answer 'yes' or 'on track' first.","One caveat if it's real; zero if it isn't.","Vague reassurance reads as evasion to a CEO."],"focus":["concision","precision"],"placeholder":"On track. One watch item: the comp rollout slips a week."},
    {"id":"concise-sales-senior-10","level":"senior","profession":"sales","title":"The bloated proposal summary","scenario":"Your proposal's executive summary is 300 words of company narrative before the offer. The buyer skims summaries; yours makes her hunt for the price and the outcome.","task":"Cut it to a 3-sentence summary: outcome, offer, payback.","tips":["The outcome and the number are the summary; the rest is body copy.","Company narrative belongs on the About slide, not the summary.","If she reads only three sentences, these are the three."],"focus":["concision","impact"]},
    {"id":"concise-sales-senior-11","level":"senior","profession":"sales","title":"The kickoff line that sprawls","scenario":"Your kickoff keynote's key message is 40 words long: \"This year, in many ways, is going to be about all of us coming together to really focus on driving expansion across our existing base of valued customers.\" It won't stick.","task":"Cut it to a message under 10 words that a seller can repeat.","tips":["A rallying line is short or it's forgotten.","Cut 'in many ways,' 'really,' 'valued' — pure padding.","End on the verb and the target."],"focus":["concision","impact"],"placeholder":"This year we expand the base."},
    {"id":"concise-sales-senior-12","level":"senior","profession":"sales","title":"The circular pipeline explanation","scenario":"Explaining a pipeline gap, you write: \"The reason pipeline is down is because we have less pipeline than we did, which is due to the fact that fewer opportunities were created.\" It circles without landing a cause.","task":"Rewrite it as one sentence naming the actual cause.","tips":["'Due to the fact that' is 'because.'","Don't restate the symptom as its own cause.","Name the real driver: fewer campaigns, a rep gap, a market shift."],"focus":["concision","precision"]},
    {"id":"concise-sales-senior-13","level":"senior","profession":"sales","title":"Trimming the negotiation email","scenario":"Your email to the customer's procurement lead is 180 words to propose one concession in exchange for a signature this quarter. Buried politeness and preamble hide the trade.","task":"Cut it to under 50 words that state the trade plainly.","tips":["Lead with the trade: we give X, you give Y, by when.","Cut the preamble; procurement respects directness.","One sentence of warmth at the end, if any."],"focus":["concision","clarity"]},
    {"id":"concise-sales-senior-14","level":"senior","profession":"sales","title":"The adjective-heavy win note","scenario":"Your win announcement is stuffed with intensifiers: \"an incredibly massive, truly game-changing, absolutely landmark deal.\" The number is what's impressive; the adjectives cheapen it.","task":"Rewrite the announcement letting the facts carry the weight, no intensifiers.","tips":["Delete 'incredibly,' 'truly,' 'absolutely' — the number is the drama.","State the size and the logo; readers supply the awe.","Intensifiers signal you don't trust the fact."],"focus":["concision","impact"],"placeholder":"We signed Fortis: $4.2M ARR, our largest deal ever."},
    {"id":"concise-sales-senior-15","level":"senior","profession":"sales","title":"The over-explained decline","scenario":"You're declining a customer's discount request, and your draft spends 120 words explaining pricing philosophy before the 'no.' The length reads as guilt and invites negotiation.","task":"Rewrite it as a clean two-sentence decline with a brief reason.","tips":["Say no early; a buried no reads as a maybe.","One reason, not a philosophy lecture.","Offer an alternative in one line if there is one."],"focus":["concision","clarity"]},
    {"id":"concise-sales-senior-16","level":"senior","profession":"sales","title":"The passive-voice status","scenario":"Your deal status reads: \"It was determined that the contract will be reviewed and a decision is expected to be made by their team.\" No one owns anything; it's all passive.","task":"Rewrite it in active voice naming who does what by when.","tips":["Passive voice hides the actor — name them.","'It was determined' — by whom? Say it.","Active status reads as controlled; passive reads as adrift."],"focus":["concision","clarity"],"placeholder":"Their CFO reviews the contract Thursday and decides by Friday."},
    {"id":"concise-sales-senior-17","level":"senior","profession":"sales","title":"Cutting the board pre-read","scenario":"Your board pre-read is three pages to make three points. Each point is smothered in context. Directors want the three points in three tight paragraphs, context on request.","task":"Compress each of the three points to a two-sentence paragraph.","tips":["Point then one line of proof — no third sentence.","Move deep context to an appendix directors can ignore.","Three tight paragraphs beat three pages every time."],"focus":["concision","structure"]},
    {"id":"concise-sales-senior-18","level":"senior","profession":"sales","title":"The redundant executive-summary opener","scenario":"Your RFP summary opens: \"In this response, we are pleased to present our comprehensive solution which we believe represents a compelling offering.\" Zero information, pure filler.","task":"Replace it with a first sentence that states why you win for them.","tips":["'We are pleased to present' says nothing — cut it whole.","Open with their requirement and your answer to it.","Committees score content, not pleasantries."],"focus":["concision","audience"]},
    {"id":"concise-sales-senior-19","level":"senior","profession":"sales","title":"The bloated Slack thread summary","scenario":"You're summarizing a long deal-strategy Slack thread for the sponsor. Your draft recaps every message. She needs the decision reached and the one open question, not the transcript.","task":"Write a 2-sentence summary: the decision and the open item.","tips":["A summary is not a transcript — extract, don't replay.","One decision, one open question; drop the deliberation.","She'll open the thread if she wants the detail."],"focus":["concision","clarity"]},
    {"id":"concise-sales-senior-20","level":"senior","profession":"sales","title":"Tightening the comp-change note","scenario":"Your note to managers about the accelerator change is 150 words of philosophy wrapping a one-line fact. Managers need the fact clean, the philosophy optional.","task":"Rewrite it leading with the one-line change, philosophy cut to one sentence.","tips":["The change is the message; the philosophy is a footnote.","Managers will be asked 'what changed?' — answer that first, briefly.","Cut everything a manager wouldn't repeat to a rep."],"focus":["concision","clarity"],"placeholder":"Effective Feb 1, accelerators start at 100% of quota, not 90%."},
    {"id":"concise-sales-senior-21","level":"senior","profession":"sales","title":"The analyst quote that rambles","scenario":"A reporter asks for a one-line reaction to a competitor's acquisition. Your draft is three sentences of hedged market context. Editors will cut it to nothing or misquote the fragment.","task":"Write one clean, quotable sentence — under 20 words.","tips":["Give the editor a sentence they can't shorten wrongly.","One idea, plain words, no clauses to trim.","If it needs a second sentence, it isn't a quote yet."],"focus":["concision","impact"]},
    {"id":"concise-sales-senior-22","level":"senior","profession":"sales","title":"The over-caveated risk call","scenario":"Asked the biggest risk to the quarter, you answer in 80 words with four qualifiers before naming it. By the time the risk appears, the CEO has lost the thread.","task":"Rewrite it as one sentence: the risk, quantified, no wind-up.","tips":["Name the risk in the first three words.","One number sizes it; qualifiers dilute it.","Offer detail after — don't front-load the hedge."],"focus":["concision","precision"],"placeholder":"The Averline expansion — $2.1M, their CFO gone quiet."},
    {"id":"concise-sales-senior-23","level":"senior","profession":"sales","title":"Halving the territory FAQ answer","scenario":"A rep asks how the territory change affects their top account. Your written answer is a paragraph of policy before the plain answer: 'it stays yours.' They needed line one, not paragraph one.","task":"Rewrite it leading with the plain answer, policy trimmed to one clause.","tips":["Answer the specific question first: yes, it's yours.","Policy is backup, not the opener.","Reps forward clear answers; they escalate confusing ones."],"focus":["concision","audience"]},
    {"id":"concise-sales-senior-24","level":"senior","profession":"sales","title":"The wordy investor talking point","scenario":"Your investor-day talking point on net revenue retention runs 50 words with three subordinate clauses. Investors want the number and its one implication, cleanly.","task":"Cut it to one sentence: the metric and what it means.","tips":["Lead with the number; strip the setup.","One implication — durable growth without new logos.","Subordinate clauses hide the point; make it the main clause."],"focus":["concision","precision"],"placeholder":"NRR is 115% — our existing base grows even before we add a customer."},
    {"id":"concise-sales-senior-25","level":"senior","profession":"sales","title":"The escalation summary that overshares","scenario":"Your escalation heads-up to the CEO includes the full email history, three internal opinions, and a timeline. He needs three lines before the call: what they want, our position, the ask of him.","task":"Cut it to three lines: their want, our position, your ask of the CEO.","tips":["He's minutes from the call — give him only what he'll use.","Drop the internal opinions; give one clear position.","End with the single thing you need him to do or say."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-sales-senior-01","level":"senior","profession":"sales","title":"The vague pipeline claim","scenario":"Your board slide says \"pipeline is significantly stronger than last quarter.\" A director will ask 'how much, and where.' Vague intensifiers invite exactly the question you can't answer on the spot.","task":"Rewrite the claim with the specific number, comparison, and where the strength sits.","tips":["Replace 'significantly' with the coverage ratio and the delta.","Say where: which segment drove the increase.","Anticipate the follow-up and put the answer in the claim."],"focus":["precision","clarity"],"placeholder":"Coverage is 3.4x, up from 2.6x, driven mostly by mid-market —"},
    {"id":"precision-sales-senior-02","level":"senior","profession":"sales","title":"Data to one insight","scenario":"Your win/loss dashboard shows 14 metrics to the exec team. The insight — you lose late-stage enterprise deals on procurement timelines, not product — is buried. You're presenting the data instead of the finding.","task":"Write the one-sentence insight the 14 metrics actually support.","tips":["A dashboard is evidence; the insight is your job to state.","Name the pattern, not the panels.","Lead with the finding, then cite the two numbers that prove it."],"focus":["precision","impact"],"placeholder":"We lose enterprise deals in procurement, not in evaluation — 8 of 11 losses stalled after technical win."},
    {"id":"precision-sales-senior-03","level":"senior","profession":"sales","title":"What / So What / Now What","scenario":"You tell the CEO \"enterprise win rate dropped to 19%.\" He asks: so what, and what now? Your instinct is to repeat the number. He needs the implication and the action.","task":"Write a 3-sentence answer: the fact, its consequence, and the action you're taking.","tips":["What: the number, once.","So what: what it costs the quarter or the plan.","Now what: the specific move, with an owner and a date."],"focus":["precision","structure"]},
    {"id":"precision-sales-senior-04","level":"senior","profession":"sales","title":"The skeptic test on ROI","scenario":"Your proposal claims \"customers typically see a 3x return.\" A skeptical CFO will ask: which customers, over what period, measured how. 'Typically' won't survive her scrutiny.","task":"Rewrite the claim so it passes the skeptic test — named basis, timeframe, method.","tips":["Ground 'typically' in a real cohort and count.","State the timeframe and what's counted as return.","A claim you can source beats a claim you can only assert."],"focus":["precision","audience"],"placeholder":"Across 40 mid-market customers, median processing cost fell 34% within 12 months —"},
    {"id":"precision-sales-senior-05","level":"senior","profession":"sales","title":"The mushy competitive claim","scenario":"Your sales narrative says \"we're much faster to deploy than the competition.\" Prospects hear it as a slogan. It needs a number and a comparison to become a differentiator.","task":"Rewrite it with a specific, defensible comparison.","tips":["'Much faster' is a claim; '6 weeks vs. their 4 months' is evidence.","Name the basis of the comparison so it's credible.","Only claim what a reference customer would confirm."],"focus":["precision","impact"]},
    {"id":"precision-sales-senior-06","level":"senior","profession":"sales","title":"The dateless commitment","scenario":"You tell the customer's COO \"we'll get the integration sorted soon.\" 'Soon' is the word that erodes trust when it slips. She needs a date and a definition of done.","task":"Rewrite the commitment with a specific date and a clear completion criterion.","tips":["Replace 'soon' with a date you can hold.","Define 'sorted' — what's true when it's done.","A precise, kept commitment rebuilds trust faster than a vague, hopeful one."],"focus":["precision","clarity"],"placeholder":"The integration passes UAT by March 14 —"},
    {"id":"precision-sales-senior-07","level":"senior","profession":"sales","title":"The forecast without a range","scenario":"You tell the board \"we're confident in the number.\" The CFO wants the range and the driver of variance. A point estimate with no range signals you haven't stress-tested it.","task":"Restate the forecast as a commit, a realistic range, and the swing factor.","tips":["Give a commit and an upside, not a single figure.","Name what moves you across the range — the swing deals.","A range with a named driver reads as rigor, not doubt."],"focus":["precision","structure"]},
    {"id":"precision-sales-senior-08","level":"senior","profession":"sales","title":"The unquantified churn risk","scenario":"You flag to the CEO that a big account is \"at some risk\" of churning. He can't act on 'some.' He needs the ARR, the probability as you see it, and the trigger.","task":"Rewrite the flag with dollars, a probability, and the specific trigger.","tips":["Size it: the ARR at stake.","Give your honest probability, not a shrug.","Name the trigger — the event that would decide it."],"focus":["precision","impact"],"placeholder":"Meridian ($1.8M) is roughly 40% to churn — the trigger is their new CIO's platform review in Q3."},
    {"id":"precision-sales-senior-09","level":"senior","profession":"sales","title":"The vague campaign result","scenario":"Marketing reports the campaign \"performed well and drove strong engagement.\" The CEO funded pipeline, not engagement. The claim needs the pipeline number and the comparison to target.","task":"Rewrite the result with the pipeline figure and how it compares to plan.","tips":["Report the metric the spend was justified on — pipeline.","'Strong' means nothing without the target it beat.","One hard number beats three soft adjectives."],"focus":["precision","audience"]},
    {"id":"precision-sales-senior-10","level":"senior","profession":"sales","title":"The evidence for the price increase","scenario":"You're recommending a 7% list increase and your support is \"the market can bear it.\" The exec team needs evidence: elasticity data, win-rate impact, competitor benchmarks.","task":"Write the three specific pieces of evidence that back the recommendation.","tips":["Each claim needs a source: elasticity from X, benchmark from Y.","Quantify the downside risk, not just the upside.","'The market can bear it' is a hope until the data says so."],"focus":["precision","structure"]},
    {"id":"precision-sales-senior-11","level":"senior","profession":"sales","title":"The imprecise attribution claim","scenario":"You tell sales managers \"marketing sourced a lot of the pipeline this quarter.\" They're skeptical and 'a lot' invites the fight. A precise, sourced number ends the argument.","task":"Rewrite it with the specific sourced-pipeline figure and share of total.","tips":["Give the dollar figure and the percentage of total pipeline.","State the attribution rule so it's not hand-waving.","Invite the audit — precision earns the skeptic's trust."],"focus":["precision","audience"],"placeholder":"Marketing sourced $6.2M of $18M new pipeline this quarter — 34%, under our first-touch rule."},
    {"id":"precision-sales-senior-12","level":"senior","profession":"sales","title":"The soft ramp assumption","scenario":"Your headcount ask assumes new AEs \"ramp reasonably quickly.\" The CFO will model the payback and needs the actual ramp curve, not a comfortable word.","task":"Restate the assumption with the specific ramp: months to productivity and to full quota.","tips":["Replace 'reasonably quickly' with the month-by-month curve.","Base it on your historical ramp, and say so.","A precise assumption can be checked; a soft one gets discounted."],"focus":["precision","clarity"]},
    {"id":"precision-sales-senior-13","level":"senior","profession":"sales","title":"The generic loss reason","scenario":"Your loss debrief says the deal was lost due to \"pricing and fit issues.\" That's two vague buckets. The exec team needs the specific deciding factor to act on it.","task":"Rewrite it naming the single deciding factor with a concrete detail.","tips":["'Pricing issues' — was it list price, terms, or a competitor's discount? Say which.","One deciding factor beats two vague contributors.","Specific losses drive specific fixes."],"focus":["precision","impact"]},
    {"id":"precision-sales-senior-14","level":"senior","profession":"sales","title":"The unsupported market claim","scenario":"Your investor-day script says \"our market is growing rapidly.\" Investors have seen every deck say that. It needs a specific TAM figure, growth rate, and source.","task":"Rewrite the claim with a sized market, a growth rate, and a source.","tips":["'Rapidly' is a filler; a CAGR with a source is evidence.","Cite the analyst or basis — investors check.","Distinguish the whole market from your serviceable slice."],"focus":["precision","audience"]},
    {"id":"precision-sales-senior-15","level":"senior","profession":"sales","title":"The vague QBR outcome","scenario":"Your QBR opens: \"You've seen great results with our platform this year.\" The customer's CFO wants the number in her metric. 'Great results' sounds like vendor talk.","task":"Rewrite it with the specific outcome delivered, in the customer's own metric.","tips":["Use their KPI: cost, throughput, hours — not your feature usage.","One measured outcome beats a page of adjectives.","If you can't measure it, don't claim it."],"focus":["precision","audience"],"placeholder":"This year you processed 22% more orders at 18% lower cost per order —"},
    {"id":"precision-sales-senior-16","level":"senior","profession":"sales","title":"The hand-wave on the miss","scenario":"Explaining the miss, you say \"a couple of big deals didn't come through.\" The board needs the count, the dollars, and why. Vagueness on a miss reads as evasion.","task":"Rewrite it with the exact deals, dollars, and the reason each slipped.","tips":["Name the count and the combined ARR.","Give the reason per deal — not a shared excuse.","Precision on a miss reads as command, not weakness."],"focus":["precision","clarity"]},
    {"id":"precision-sales-senior-17","level":"senior","profession":"sales","title":"The intensifier-laden win rate","scenario":"You report win rate is \"dramatically improved.\" The exec team wants the points of improvement and against what baseline. 'Dramatically' hides whether it's two points or twelve.","task":"Rewrite it with the exact win rate, the prior period, and the delta.","tips":["Give the number and the baseline it improved from.","One period-over-period comparison, clearly labeled.","Let the delta be dramatic on its own if it is."],"focus":["precision","impact"],"placeholder":"Enterprise win rate rose from 19% to 27% quarter over quarter —"},
    {"id":"precision-sales-senior-18","level":"senior","profession":"sales","title":"The fuzzy partner-motion claim","scenario":"You propose a co-sell partnership arguing it will \"open up significant new pipeline.\" The exec team needs a sized, time-bound estimate and the basis for it.","task":"Rewrite it with an estimated pipeline figure, a timeframe, and the assumption behind it.","tips":["Size the opportunity: dollars over a period.","State the assumption driving the estimate so it's testable.","'Significant' is a hope; a modeled number is a proposal."],"focus":["precision","structure"]},
    {"id":"precision-sales-senior-19","level":"senior","profession":"sales","title":"The undefined 'strategic' deal","scenario":"You ask the deal desk to approve exception terms because the deal is \"strategic.\" Everyone calls their deal strategic. You need to say precisely why this one earns the exception.","task":"Rewrite the justification with the specific strategic value, quantified.","tips":["Define 'strategic' in this case: logo, expansion path, reference value.","Attach a number — the ARR ceiling this account unlocks.","The desk approves evidence, not adjectives."],"focus":["precision","impact"]},
    {"id":"precision-sales-senior-20","level":"senior","profession":"sales","title":"The vague enablement gap","scenario":"You tell the CEO the field \"needs better enablement.\" That's unactionable. He needs the specific gap, its measured cost, and the fix.","task":"Rewrite it naming the specific gap, the evidence it's costing you, and the fix.","tips":["Name the exact skill or content missing.","Quantify the cost: deals lost, cycle length, ramp time.","Pair the gap with a specific, sized intervention."],"focus":["precision","structure"]},
    {"id":"precision-sales-senior-21","level":"senior","profession":"sales","title":"The unquantified upsell claim","scenario":"You tell the board there's \"a lot of upsell potential in the base.\" They want the sized opportunity, the basis, and the plan to capture it.","task":"Rewrite it with the quantified opportunity and the assumption behind the estimate.","tips":["Size it: the addressable expansion ARR in the current base.","State how you sized it — penetration gap, product attach.","'A lot' is a feeling; a number is a plan."],"focus":["precision","impact"],"placeholder":"The base has roughly $9M of second-product upsell — 60% of accounts run only one product."},
    {"id":"precision-sales-senior-22","level":"senior","profession":"sales","title":"The soft SLA in the contract talk","scenario":"In a negotiation you offer \"strong uptime and responsive support.\" The customer's CTO needs the actual SLA numbers to compare. Soft language reads as an evasion of commitment.","task":"Rewrite the offer with specific uptime and response-time commitments.","tips":["State the uptime percentage and the response-time targets.","Precision here reads as confidence in your operations.","Only commit to what operations will actually honor."],"focus":["precision","clarity"]},
    {"id":"precision-sales-senior-23","level":"senior","profession":"sales","title":"The board metric with no context","scenario":"Your slide shows \"CAC payback: 14 months\" with no comparison. A director can't tell if that's good. The number needs a benchmark or a trend to carry meaning.","task":"Rewrite the metric line with the comparison that gives it meaning.","tips":["A metric alone is trivia; a metric versus a benchmark is insight.","Compare to prior period or to the plan.","Say plainly whether the trend is good and why."],"focus":["precision","clarity"],"placeholder":"CAC payback is 14 months, down from 19 a year ago and below our 18-month target."},
    {"id":"precision-sales-senior-24","level":"senior","profession":"sales","title":"The evidence-free confidence","scenario":"You tell the CEO you're confident the reorg will lift productivity, but you offer no basis. He'll fund it if you show the mechanism and the expected, measurable lift.","task":"Rewrite it with the specific expected lift and the evidence supporting it.","tips":["Attach a number to 'lift' — percentage, timeframe, metric.","Show the mechanism: why the new structure produces the lift.","Cite a comparable or a pilot if you have one."],"focus":["precision","impact"]},
    {"id":"precision-sales-senior-25","level":"senior","profession":"sales","title":"The imprecise ask of the CFO","scenario":"You ask the CFO to \"free up some budget\" for a new tool. 'Some' is unfundable. She needs the exact amount, the period, and the return you're promising.","task":"Rewrite the ask with the specific amount, timeframe, and expected return.","tips":["Name the number and when you need it.","Pair the cost with the quantified return in the same sentence.","A precise ask is fundable; a vague one gets deferred."],"focus":["precision","clarity"],"placeholder":"I'm asking for $180K this year for the intent-data platform, against roughly $1.4M in incremental pipeline."}
  ],
  "executive-presence": [
    {"id":"presence-sales-senior-01","level":"senior","profession":"sales","title":"The menu with no recommendation","scenario":"You bring the exec team three GTM options — go upmarket, double down on mid-market, or add a partner motion — laid out evenly with pros and cons. They look at you: which one do you recommend? A neutral menu abdicates your role.","task":"Rewrite the close so you recommend one option and say why.","tips":["Lay out the options, then plant a flag: 'I recommend the second.'","Give the one reason that tips it, not a balanced weighing.","Executives hired you for judgment, not a comparison table."],"focus":["impact","clarity"],"placeholder":"Of the three, I recommend going upmarket — here's the one reason it wins:"},
    {"id":"presence-sales-senior-02","level":"senior","profession":"sales","title":"Owning the missed number","scenario":"Presenting the miss to the board, your draft leans on external factors — market softness, a competitor's move, procurement delays. It reads as a search for cover. Presence means owning what you controlled.","task":"Rewrite the opening so you own the controllable part before naming external factors.","tips":["Name what you'd do differently first — it earns the right to context.","Own the controllable, attribute the rest honestly and briefly.","Boards trust leaders who don't hide behind the market."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-03","level":"senior","profession":"sales","title":"Fact versus judgment in the forecast","scenario":"Your forecast note blends what's true with what you believe: \"The deal is strong and will close, the champion is fully bought in, and it's basically done.\" The CEO can't tell verified fact from your read.","task":"Rewrite it separating what's confirmed from what's your judgment call.","tips":["Label the facts: signed, in redlines, verbally committed.","Label your read as a read: 'my judgment is 80%.'","Blurring the two is how surprises happen at the board level."],"focus":["precision","clarity"]},
    {"id":"presence-sales-senior-04","level":"senior","profession":"sales","title":"Signposting the board section","scenario":"You launch into your revenue update with no roadmap, and directors don't know how many points are coming or where you're headed. A quick signpost gives your section authority and lets them follow.","task":"Write a one-sentence signpost that frames the three things you'll cover.","tips":["Tell them the shape before the content: 'three things — result, risk, ask.'","Signposting reads as control, not filler.","Then deliver in exactly that order."],"focus":["structure","impact"],"placeholder":"Three things on revenue: where we landed, the one risk to next quarter, and one ask."},
    {"id":"presence-sales-senior-05","level":"senior","profession":"sales","title":"The apologetic recommendation","scenario":"You recommend the price increase but hedge it: \"This might be a bit aggressive, and I could be wrong, but maybe we should consider possibly raising prices.\" The hedging undercuts the recommendation before it lands.","task":"Rewrite it as a confident recommendation that still invites challenge.","tips":["State it plainly: 'I recommend a 7% increase.'","Confidence and openness coexist: 'here's my reasoning — push on it.'","Hedging protects you and costs you credibility."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-06","level":"senior","profession":"sales","title":"Taking the room in the QBR","scenario":"In the customer QBR, their CFO challenges your value claim. Your draft response is deferential and retreating. Presence means holding your ground with evidence, respectfully, not folding.","task":"Write a 2-3 sentence response that holds the claim with evidence, without defensiveness.","tips":["Acknowledge the challenge, then stand on the number.","Cite the proof calmly — no rush, no retreat.","Folding under one push tells the room the claim was soft."],"focus":["impact","precision"]},
    {"id":"presence-sales-senior-07","level":"senior","profession":"sales","title":"The CEO wants your call","scenario":"The CEO asks whether to accept a customer's demand for a custom SLA that would set a precedent. Your draft lists considerations on both sides and stops. He wants your recommendation, not a briefing.","task":"Write a 2-3 sentence answer that gives your recommendation and the key reason.","tips":["Answer the decision: 'I'd decline it, and hold the line.'","One reason that carries the call — the precedent risk.","A well-reasoned wrong call beats a non-answer."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-08","level":"senior","profession":"sales","title":"Presence in the missed-quarter all-hands","scenario":"You're addressing the whole revenue org after a missed quarter. Your draft is either falsely upbeat or grim. Presence is level: honest about the miss, clear on the plan, steady in tone.","task":"Write a 3-4 sentence opening that is honest, steady, and forward-looking.","tips":["Name the miss without spin and without despair.","Steady tone signals control more than any content does.","Move quickly to the plan — that's what calms a room."],"focus":["impact","audience"]},
    {"id":"presence-sales-senior-09","level":"senior","profession":"sales","title":"The neutral pricing memo","scenario":"Your pricing-strategy memo presents four models with even weighting and no view. The exec team reads it and asks what you actually think. Neutrality at this altitude reads as avoidance.","task":"Rewrite the conclusion to commit to one model and defend it in two sentences.","tips":["Pick the model and say so in the first line of the conclusion.","Defend it against the strongest alternative, briefly.","A committed view can be argued; a neutral menu can only be re-litigated."],"focus":["impact","structure"]},
    {"id":"presence-sales-senior-10","level":"senior","profession":"sales","title":"Holding position with the customer CEO","scenario":"In a big-deal negotiation, the customer's CEO pushes for a 30% discount 'or no deal.' Your draft either caves or gets rigid. Presence is calm, principled, and holds value while keeping the room.","task":"Write a 2-3 sentence response that holds on price while keeping the relationship warm.","tips":["Acknowledge the ask, then reframe around value, not defensiveness.","Offer a trade, not a cave: term, volume, or scope for price.","Calm and firm beats either flustered or rigid."],"focus":["impact","audience"]},
    {"id":"presence-sales-senior-11","level":"senior","profession":"sales","title":"The under-owned reorg","scenario":"You're announcing a territory redesign and your draft attributes it to 'leadership' and 'the plan' as if it happened to you. Sellers respect a leader who owns the decision and stands behind it.","task":"Rewrite the opening so you own the decision in the first person.","tips":["Say 'I decided,' not 'it was decided.'","Owning it invites accountability — which is the point.","Distance from your own decision reads as weakness to a field team."],"focus":["impact","clarity"],"placeholder":"I've decided to redraw the territories, and I'll tell you exactly why."},
    {"id":"presence-sales-senior-12","level":"senior","profession":"sales","title":"The buried judgment in the deal review","scenario":"In the big-deal review, the sponsor asks whether the deal will close this quarter. Your draft recites stage, activities, and next steps but never states your judgment. Presence is stating your call and standing on it.","task":"Write a 2-sentence answer that gives your judgment and the confidence level.","tips":["State your call: 'closes this quarter, 75%.'","Then the one thing that would change it.","Activities are not a forecast — your judgment is."],"focus":["impact","precision"]},
    {"id":"presence-sales-senior-13","level":"senior","profession":"sales","title":"The wobbly answer to the analyst","scenario":"An analyst asks whether your usage-based pricing shift is working. Your draft is noncommittal — 'early days, mixed signals, hard to say.' Presence means a clear read, honestly caveated, not a shrug.","task":"Write a 2-3 sentence answer with a clear read and an honest caveat.","tips":["Give a directional read: 'working, with one soft spot.'","Caveat it honestly, but don't hide behind 'too early.'","Analysts respect a leader with a view they can pressure-test."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-14","level":"senior","profession":"sales","title":"Recommending against the CEO's instinct","scenario":"The CEO wants to chase a splashy logo you believe is a poor fit and a distraction. Your draft softens your view to avoid friction. Presence is disagreeing clearly, with respect and reasons.","task":"Write a 2-3 sentence recommendation that disagrees with the CEO's instinct, respectfully.","tips":["State your disagreement plainly, then the reason.","Respect the instinct — name what's appealing — then counter it.","Yielding to avoid friction is how bad bets get funded."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-15","level":"senior","profession":"sales","title":"The signposted kickoff","scenario":"You open your sales kickoff by diving into content with no frame. A room of 300 doesn't know where you're taking them. A signpost gives the keynote structure and you command.","task":"Write a signpost opening that frames the three parts of your keynote.","tips":["Frame the arc: 'where we won, where we lost, what we change.'","A framed keynote reads as led; a rambling one reads as improvised.","Deliver the three in the order you named."],"focus":["structure","impact"]},
    {"id":"presence-sales-senior-16","level":"senior","profession":"sales","title":"Fact and judgment on the churn call","scenario":"Briefing the CEO on a churn risk, your draft mixes confirmed signals with your interpretation as if equal: 'they're unhappy, they're leaving, it's the CSM's fault.' He needs the fact/judgment line drawn.","task":"Rewrite it labeling what's confirmed versus what's your interpretation.","tips":["Facts: what they said, what they signed, what the data shows.","Judgment: your read on cause and likelihood, labeled as such.","Presenting a guess as a fact is how leaders lose credibility."],"focus":["precision","clarity"]},
    {"id":"presence-sales-senior-17","level":"senior","profession":"sales","title":"The recommendation the CFO can act on","scenario":"You present the CFO a spend analysis and stop at 'here's the data.' She wants to know what you'd do. Presence is turning analysis into a clear recommendation with your name on it.","task":"Write a 2-3 sentence recommendation that states the move and owns it.","tips":["End analysis with a decision, not a data dump.","'I recommend shifting $2M from events to digital' — own it.","The CFO can debate a recommendation; she can't act on data alone."],"focus":["impact","structure"],"placeholder":"My recommendation: move $2M from field events to digital demand-gen this half."},
    {"id":"presence-sales-senior-18","level":"senior","profession":"sales","title":"Steady under the board's heat","scenario":"A director grills you on why enterprise stalled, in a sharp tone. Your draft response is either flustered or combative. Presence is answering the substance calmly and not taking the heat personally.","task":"Write a 2-3 sentence response that stays composed and answers the substance.","tips":["Answer the question, not the tone.","Composure under pressure is itself the message.","Match rigor to their intensity, not emotion to it."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-19","level":"senior","profession":"sales","title":"The recommendation buried in options","scenario":"Your comp-redesign proposal to the exec team lists five plan structures with tradeoffs and no lead choice. They want your design, not a catalog. Presence is designing, then defending.","task":"Write a 2-3 sentence close that names your recommended design and the tradeoff you accept.","tips":["Recommend one design and state it first.","Name the tradeoff you're consciously making — that's judgment on display.","A catalog with no pick tells them you couldn't decide."],"focus":["impact","structure"]},
    {"id":"presence-sales-senior-20","level":"senior","profession":"sales","title":"Owning the pipeline shortfall","scenario":"Pipeline for next quarter is thin and you know it. Your draft to the CEO frames it as a market issue. Presence is owning the coverage gap and coming with a plan, not an explanation.","task":"Write a 2-3 sentence message that owns the gap and leads with the plan.","tips":["Name the gap in your own numbers, not the market's.","Come with the fix, not just the diagnosis.","Ownership plus a plan reads as leadership; explanation reads as excuse."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-21","level":"senior","profession":"sales","title":"The confident 'no' to the discount","scenario":"A strategic customer's CFO demands an off-policy discount. Your draft is apologetic and wobbly. Presence is a clear, respectful no that holds the value and keeps the door open.","task":"Write a 2-3 sentence response that declines firmly and reframes around value.","tips":["Say no clearly — a wobbly no invites a harder push.","Reframe on value delivered, not on your inability to flex.","Firmness with warmth keeps the relationship and the price."],"focus":["impact","audience"]},
    {"id":"presence-sales-senior-22","level":"senior","profession":"sales","title":"The judgment call on the RFP","scenario":"The team asks whether to bid on a large but poor-fit RFP. Your draft weighs it endlessly. Presence is making the call — bid or pass — and giving the team a clear reason.","task":"Write a 2-sentence decision: bid or pass, and the one reason.","tips":["Make the call in the first word.","One reason that decides it — fit, odds, or opportunity cost.","A clear pass frees the team more than an endless maybe."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-23","level":"senior","profession":"sales","title":"The framed investor answer","scenario":"An investor asks how you'll sustain growth. Your draft rambles across tactics. Presence is naming the two or three levers, signposted, and standing behind them as your strategy.","task":"Write a 2-3 sentence answer that signposts your growth levers and commits to them.","tips":["Frame it: 'growth rests on two levers.'","Name them, then say why you're confident in each.","Signposting plus commitment reads as a leader with a plan."],"focus":["structure","impact"]},
    {"id":"presence-sales-senior-24","level":"senior","profession":"sales","title":"Owning the enablement decision","scenario":"You're cutting a legacy enablement program the field is attached to. Your draft hides behind 'we're evaluating options.' Presence is owning the decision and explaining the reasoning directly.","task":"Write a 2-3 sentence message that owns the decision and gives the reason.","tips":["State the decision as yours: 'I'm sunsetting the program.'","Give the reason honestly — data, cost, or focus.","Hiding a decision behind 'evaluating' insults the people affected."],"focus":["impact","clarity"]},
    {"id":"presence-sales-senior-25","level":"senior","profession":"sales","title":"The recommendation under uncertainty","scenario":"The CEO asks whether to enter a new vertical you have imperfect data on. Your draft either overclaims certainty or refuses to commit. Presence is a clear recommendation that's honest about the uncertainty.","task":"Write a 2-3 sentence recommendation that commits while naming the uncertainty.","tips":["Give a recommendation despite incomplete data — that's the job.","State the key uncertainty and how you'd de-risk it.","'I don't have perfect data, but I'd move — here's why' is presence."],"focus":["impact","precision"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-sales-senior-01","level":"senior","profession":"sales","title":"The board asks the question you dread","scenario":"A director asks point-blank: \"Are we going to miss again next quarter?\" Your instinct is to pivot to pipeline mechanics. The question is binary, and dodging it costs you more than an honest answer.","task":"Write a spoken answer that addresses the yes/no first, then the basis.","tips":["Answer the question asked: 'No — and here's the coverage that backs that.'","Pivoting to mechanics before answering reads as evasion.","One honest caveat is fine; a dodge is not."],"focus":["clarity","impact"],"placeholder":"No, and I'll tell you what makes me confident:"},
    {"id":"pressure-sales-senior-02","level":"senior","profession":"sales","title":"Pushback on the price increase","scenario":"You recommend a 7% increase and a director snaps: \"You'll tank win rates.\" Your draft gets defensive. The strong move is to answer with the specific elasticity evidence, calmly.","task":"Write a 2-3 sentence response that answers the concern with specifics, not defensiveness.","tips":["Meet the objection with data, not with 'I disagree.'","Cite the elasticity or benchmark that bounds the risk.","Acknowledge the real risk, then show why it's contained."],"focus":["precision","impact"]},
    {"id":"pressure-sales-senior-03","level":"senior","profession":"sales","title":"The honest 'I don't know'","scenario":"In the forecast call the CEO asks why a specific deal slipped, and you genuinely don't know yet. Your draft manufactures a plausible-sounding reason. Better: say you don't know, and give the path to find out.","task":"Write a 2-sentence answer that admits the gap and commits to a specific follow-up.","tips":["'I don't know yet' with a path beats a confident guess.","Name when you'll have the answer and how.","Manufactured reasons collapse the moment they're checked."],"focus":["clarity","precision"],"placeholder":"I don't have the real reason yet — I'll have the debrief from the AE by end of day and circle back."},
    {"id":"pressure-sales-senior-04","level":"senior","profession":"sales","title":"The customer CEO's sharp challenge","scenario":"In a QBR the customer's CEO says: \"Frankly, I'm not sure we're getting our money's worth.\" Your draft defends every feature. The move is to answer the actual doubt — value — with their own numbers.","task":"Write a 2-3 sentence response that addresses the value question directly, with evidence.","tips":["Answer the doubt he raised — value — not the features you're proud of.","Lead with the outcome in his metric.","Invite him to define what 'worth it' looks like, then meet it."],"focus":["audience","impact"]},
    {"id":"pressure-sales-senior-05","level":"senior","profession":"sales","title":"The loaded question at the all-hands","scenario":"At the all-hands after the miss, an employee asks: \"Should we be worried about layoffs?\" Your draft deflects to strategy. People asked about their jobs; they deserve a direct answer.","task":"Write a 2-3 sentence answer that addresses the job-security question honestly and directly.","tips":["Answer the question they asked, not the one you'd prefer.","Be honest — if you can't promise, say what you can commit to.","Deflection on a fear question breeds more fear."],"focus":["clarity","audience"]},
    {"id":"pressure-sales-senior-06","level":"senior","profession":"sales","title":"The analyst's competitive trap","scenario":"An analyst asks: \"Isn't Coretex just eating your lunch in the enterprise?\" Your draft either dismisses it or gets rattled. The move is to concede what's true, then counter with specifics.","task":"Write a 2-3 sentence answer that concedes the valid part and counters with evidence.","tips":["Concede what's true — it buys credibility for the counter.","Counter with a specific: a segment or metric where you lead.","Dismissing a real threat makes you look out of touch."],"focus":["impact","precision"]},
    {"id":"pressure-sales-senior-07","level":"senior","profession":"sales","title":"The CFO doubts your ramp math","scenario":"Reviewing your headcount ask, the CFO says: \"Your ramp assumptions are optimistic.\" Your draft insists they're fine. Better: engage the specific assumption she doubts and show the basis.","task":"Write a 2-3 sentence response that engages her specific doubt with your historical data.","tips":["Ask which assumption, or name the one she likely means.","Show the historical ramp that grounds it.","Offer to stress-test it with her — that reads as confidence."],"focus":["precision","audience"]},
    {"id":"pressure-sales-senior-08","level":"senior","profession":"sales","title":"The deal that fell apart — live","scenario":"In the pipeline review the CEO asks why the deal you called 'committed' just died. You're tempted to blame the customer. The move is to answer what actually happened and what you misread.","task":"Write a 2-3 sentence answer that owns the misread and states the lesson.","tips":["Own what you got wrong in the call, not just what the customer did.","One clear lesson, stated, rebuilds trust in your forecast.","Blaming the customer for your 'committed' call reads as denial."],"focus":["clarity","impact"]},
    {"id":"pressure-sales-senior-09","level":"senior","profession":"sales","title":"The unexpected board follow-up","scenario":"You present NRR at 115%; a director asks: \"Strip out the one mega-account — what's the number then?\" You don't have it memorized. Answer the question, honestly, without bluffing a figure.","task":"Write a 2-sentence answer that handles the question without fabricating a number.","tips":["Don't invent a figure under pressure — say you'll pull it.","Give the directional truth if you know it: 'still above 110%, I believe.'","Commit to the exact number by a specific time."],"focus":["precision","clarity"]},
    {"id":"pressure-sales-senior-10","level":"senior","profession":"sales","title":"The negotiation ultimatum","scenario":"The customer's procurement lead says: \"Match the competitor's price today or we walk.\" Your draft either caves or bluffs. The move is to answer the pressure calmly and test what's real.","task":"Write a 2-3 sentence response that holds composure and probes the ultimatum.","tips":["Don't react to the deadline as if it's fixed — test it.","Answer with a question or a trade, not a cave.","Composure signals you've been here before."],"focus":["impact","audience"]},
    {"id":"pressure-sales-senior-11","level":"senior","profession":"sales","title":"The CEO's rapid-fire follow-ups","scenario":"You give one answer in the forecast call and the CEO fires three follow-ups in a row. Your draft tries to answer all at once and tangles. The move is to take them one at a time, cleanly.","task":"Write how you'd handle the volley: answer the first crisply, then invite the next.","tips":["Answer one question fully before the next — don't braid them.","'That's the first — the second was…' keeps you in control.","Crisp serial answers read as command; a tangle reads as overwhelm."],"focus":["clarity","structure"]},
    {"id":"pressure-sales-senior-12","level":"senior","profession":"sales","title":"The hostile churn question","scenario":"A board member asks: \"Why did we lose Meridian — was it the product or the account team?\" Your draft protects the team vaguely. The move is to answer the real cause honestly, even if it's uncomfortable.","task":"Write a 2-3 sentence answer that names the real cause without scapegoating.","tips":["Name the actual cause — product, coverage, or fit.","Don't scapegoat the team, and don't hide a real gap.","An honest cause lets the board help; a vague one invites more digging."],"focus":["clarity","precision"]},
    {"id":"pressure-sales-senior-13","level":"senior","profession":"sales","title":"The 'why should we believe you' moment","scenario":"After a miss, the CEO asks why he should trust your forecast this quarter. Your draft gets emotional or over-promises. The move is to answer with what changed in your process, concretely.","task":"Write a 2-3 sentence answer grounded in the specific change that makes this forecast better.","tips":["Answer with a process change, not a promise or a plea.","Name the specific new discipline — deal inspection, criteria.","Over-promising after a miss deepens the credibility hole."],"focus":["precision","impact"]},
    {"id":"pressure-sales-senior-14","level":"senior","profession":"sales","title":"The interrupting director","scenario":"You're two sentences into your pipeline read and a director interrupts: \"Just tell me if we're covered.\" Your draft resists and continues the prepared flow. The move is to answer their question, now, then resume.","task":"Write how you'd pivot: answer the coverage question immediately, then offer the detail.","tips":["Give them what they asked for first — coverage, yes or no.","Then offer to continue: 'the detail's here if useful.'","Plowing through your script after an interruption reads as deaf."],"focus":["audience","clarity"],"placeholder":"Yes — we're at 3.4x, covered. I'll show where it sits if that's useful."},
    {"id":"pressure-sales-senior-15","level":"senior","profession":"sales","title":"The customer's angry escalation call","scenario":"On a live call, the customer's COO vents about a failed integration before you can speak. Your draft rushes to defend the timeline. The move is to answer the emotion first, then the facts.","task":"Write a 2-3 sentence opening that acknowledges the frustration before the facts.","tips":["Acknowledge the impact on them before defending anything.","Defending the timeline before hearing them out inflames it.","Then move to facts and the fix — calmly, specifically."],"focus":["audience","impact"]},
    {"id":"pressure-sales-senior-16","level":"senior","profession":"sales","title":"The trap question on discounting","scenario":"A director asks: \"Are we buying the quarter with discounts?\" Your draft over-explains. The move is to answer the yes/no honestly with the discount trend, then the context.","task":"Write a 2-3 sentence answer that gives the honest read with the discount data.","tips":["Answer directly — is discounting up or not.","Cite the average discount trend, not a vibe.","Honesty on discounting builds trust for the harder quarters."],"focus":["precision","clarity"]},
    {"id":"pressure-sales-senior-17","level":"senior","profession":"sales","title":"The 'what would you do differently' question","scenario":"After a lost marquee deal, the CEO asks what you'd do differently. Your draft lists everything that went wrong externally. The move is to answer with what you'd change in your own approach.","task":"Write a 2-3 sentence answer focused on your controllable changes.","tips":["Answer about your own decisions, not the customer's.","One or two concrete changes, not a list of grievances.","Owning the controllable is what the CEO is testing for."],"focus":["clarity","impact"]},
    {"id":"pressure-sales-senior-18","level":"senior","profession":"sales","title":"The skeptical partner exec","scenario":"A potential channel partner's VP asks: \"Why won't you just compete with us six months in?\" Your draft is reassuring platitudes. The move is to answer the real fear with a concrete commitment.","task":"Write a 2-3 sentence answer that addresses the fear with a specific, verifiable commitment.","tips":["Name the fear he raised — channel conflict — and address it head-on.","Offer something concrete: a written boundary, a segment split.","Platitudes deepen a partner's suspicion; specifics reduce it."],"focus":["audience","precision"]},
    {"id":"pressure-sales-senior-19","level":"senior","profession":"sales","title":"The reorg question you can't fully answer","scenario":"After announcing the reorg, a top rep asks in the town hall: \"Will my accounts change?\" You don't have the final mapping. Answer honestly with what you know and when they'll know the rest.","task":"Write a 2-3 sentence answer that gives what's decided and a firm date for the rest.","tips":["Say what's settled and what isn't — don't fake certainty.","Commit to the date the mappings land.","'I don't know yet, here's when you will' beats a hedge."],"focus":["clarity","audience"]},
    {"id":"pressure-sales-senior-20","level":"senior","profession":"sales","title":"The CFO's cost-of-sale challenge","scenario":"The CFO asks: \"Why is our cost of sale climbing while win rates are flat?\" Your draft deflects to market conditions. The move is to answer the actual question with the real driver.","task":"Write a 2-3 sentence answer that names the real driver and what you're doing about it.","tips":["Answer the specific question — what's driving cost of sale up.","Name the driver: longer cycles, more touches, mix shift.","Pair the diagnosis with the action, briefly."],"focus":["precision","clarity"]},
    {"id":"pressure-sales-senior-21","level":"senior","profession":"sales","title":"The public misstatement to correct","scenario":"In an investor Q&A a peer exec misstates your win rate upward, and you're asked to confirm it live. Your draft lets it slide. The move is to correct it honestly and immediately, without throwing the peer under.","task":"Write a 2-3 sentence correction that fixes the number without embarrassing the peer.","tips":["Correct the record — an unchallenged wrong number is your problem later.","Do it gracefully: 'to be precise, the figure is…'","Investors trust the exec who volunteers the accurate number."],"focus":["precision","impact"]},
    {"id":"pressure-sales-senior-22","level":"senior","profession":"sales","title":"The 'is the strategy working' grilling","scenario":"A director presses: \"Two quarters into the upmarket shift — is it working or not?\" Your draft hedges with 'early signs.' The move is to give a clear directional read with the evidence.","task":"Write a 2-3 sentence answer with a directional verdict and the numbers behind it.","tips":["Give a verdict: 'working, with one lag.'","Cite the two metrics that support it.","'Early days' after two quarters reads as ducking the question."],"focus":["clarity","precision"]},
    {"id":"pressure-sales-senior-23","level":"senior","profession":"sales","title":"The team member's tough public question","scenario":"In your kickoff Q&A, a rep asks: \"Why should we believe this year's plan when last year's blew up?\" Your draft gets defensive. The move is to answer the fair challenge honestly.","task":"Write a 2-3 sentence answer that validates the challenge and gives a real reason to believe.","tips":["Acknowledge the fair point — last year missed.","Give a concrete reason this year differs, not a pep talk.","Defensiveness here loses the room; candor wins it."],"focus":["audience","impact"]},
    {"id":"pressure-sales-senior-24","level":"senior","profession":"sales","title":"The gotcha on a competitor's claim","scenario":"A prospect's CTO reads you a competitor's benchmark that beats yours and asks you to respond live. Your draft attacks the competitor. The move is to answer the substance and reframe on what matters.","task":"Write a 2-3 sentence answer that addresses the benchmark honestly and reframes.","tips":["Engage the number — concede or contextualize it honestly.","Reframe to the metric that matters for his use case.","Attacking the competitor instead of answering reads as evasion."],"focus":["precision","audience"]},
    {"id":"pressure-sales-senior-25","level":"senior","profession":"sales","title":"The 'what's your worst case' question","scenario":"The board asks for your worst-case revenue scenario, and your draft avoids naming a low number. The move is to answer the actual question — the real downside — with the assumptions behind it.","task":"Write a 2-3 sentence answer that names the worst-case number and what drives it.","tips":["Give the actual downside figure — avoiding it looks like hiding.","Name the two or three assumptions that produce it.","A credible worst case builds trust in your base case."],"focus":["precision","clarity"],"placeholder":"Worst case is $11.8M — that assumes both enterprise deals slip and mid-market flattens."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-sales-senior-01","level":"senior","profession":"sales","title":"The before/after for the pricing change","scenario":"You're pitching the exec team on usage-based pricing. Your draft lists features of the new model. It persuades far more as a story: here's where we are, here's the friction, here's the better world after.","task":"Write a 3-4 sentence before/after narrative that frames the pricing change as a shift to a better state.","tips":["Paint 'before' as the status quo everyone already feels is broken.","Make 'after' concrete: what a deal, a customer, a quarter looks like.","The change is the bridge between the two — not a feature list."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-02","level":"senior","profession":"sales","title":"Concrete stakes for the headcount ask","scenario":"Your headcount ask to the CFO is abstract: 'we need more capacity.' It persuades when the stakes are concrete — the specific deals you can't cover and the revenue walking out the door.","task":"Write a 2-3 sentence pitch that makes the cost of not hiring vivid and specific.","tips":["Name the deals or pipeline you're leaving uncovered.","Put a dollar figure on the inaction, not just the action.","Abstract capacity is ignorable; a named loss is not."],"focus":["impact","precision"],"placeholder":"Right now three enterprise territories have no owner — that's roughly $7M of pipeline no one is working."},
    {"id":"narrative-sales-senior-03","level":"senior","profession":"sales","title":"Pre-empting the board's objection","scenario":"You're proposing to shift spend from field events to digital. The board's strongest objection — 'events built our biggest relationships' — is real. Persuasion means naming it before they do and answering it.","task":"Write a 2-3 sentence passage that raises the strongest objection and answers it.","tips":["Name their best counter-argument yourself — it disarms it.","Answer with data or a concession, not a dismissal.","Un-raised objections fester; raised ones get resolved."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-04","level":"senior","profession":"sales","title":"The customer transformation story","scenario":"You're closing a big deal and your pitch is a feature walkthrough. The customer's CEO buys transformation, not features. Tell the story of a customer like them who went from a painful before to a better after.","task":"Write a 3-4 sentence customer story with a concrete before and after.","tips":["Pick a reference customer that mirrors this buyer's situation.","Make the 'before' pain recognizable to this CEO.","Quantify the 'after' — the transformation needs a number."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-05","level":"senior","profession":"sales","title":"Framing the reorg as opportunity","scenario":"Your territory redesign will unsettle reps. Framed as 'we're changing things,' it breeds anxiety. Framed as a before/after — from stepped-on toes to clean, winnable patches — it becomes a story reps can want.","task":"Write a 3-4 sentence framing that casts the reorg as a move to a better state for reps.","tips":["Name the current pain reps already feel — overlap, thin coverage.","Cast the new state as solving their problem, not the org's.","Change without a 'why better' reads as churn; with it, as progress."],"focus":["structure","audience"]},
    {"id":"narrative-sales-senior-06","level":"senior","profession":"sales","title":"The investor growth story","scenario":"Your investor-day narrative is a metrics recital. Investors fund a story: where the market is going, why you're positioned to win it, and what the next chapter looks like. The numbers should serve that arc.","task":"Write a 3-4 sentence growth narrative that frames the market shift and your position in it.","tips":["Open on the market change, not your company.","Position yourselves as the answer the shift demands.","End on the next chapter — where this goes if you win."],"focus":["impact","structure"]},
    {"id":"narrative-sales-senior-07","level":"senior","profession":"sales","title":"Making the churn risk vivid for the CEO","scenario":"You want the CEO to intervene on a churning account. 'It's at risk' is abstract. A short narrative — how a happy customer soured, what happens if they leave — moves him to act.","task":"Write a 3-4 sentence narrative that makes the stakes of losing the account concrete.","tips":["Tell the arc: how they went from champion to skeptic.","Make the loss concrete: the ARR, the reference value, the signal to the market.","A story he can picture prompts action; a status line doesn't."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-08","level":"senior","profession":"sales","title":"The kickoff rallying narrative","scenario":"Your kickoff keynote needs to rally 300 sellers around base expansion. A list of targets won't move them. A narrative — where we've been, the untapped opportunity in front of us, who we become if we seize it — will.","task":"Write a 3-4 sentence rallying narrative with a clear before, opportunity, and after.","tips":["Honor where the team's been before pointing forward.","Make the opportunity feel within reach, not aspirational fog.","End on identity: who the team becomes by winning this."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-09","level":"senior","profession":"sales","title":"Pre-empting the CFO's pricing objection","scenario":"You're recommending the price increase and the CFO's strongest objection is churn risk in the base. Persuasion means raising that risk yourself, sizing it, and showing why it's acceptable.","task":"Write a 2-3 sentence passage that pre-empts the churn objection with sizing.","tips":["State the objection as she'd put it, then size the real exposure.","Show the math: revenue gained versus revenue at risk.","Owning the downside makes the upside credible."],"focus":["structure","precision"]},
    {"id":"narrative-sales-senior-10","level":"senior","profession":"sales","title":"The market narrative for the analyst","scenario":"You want an analyst to write that your category is consolidating and you're the consolidator. A claim won't do it; a narrative will — the fragmentation that was, the forces pushing consolidation, your role in it.","task":"Write a 3-4 sentence market narrative the analyst could adopt.","tips":["Start with the 'before' — the fragmented market everyone knows.","Name the forces driving consolidation — make it inevitable-feeling.","Place your company as the natural winner, with a proof point."],"focus":["structure","audience"]},
    {"id":"narrative-sales-senior-11","level":"senior","profession":"sales","title":"Concrete stakes in the RFP summary","scenario":"Your RFP executive summary describes capabilities abstractly. The committee is moved by stakes: what their specific problem costs them today, and what solving it is worth. Make it concrete to them.","task":"Write a 2-3 sentence passage that makes their current cost and the payoff concrete.","tips":["Quantify their status-quo pain in their own numbers.","Frame your solution as the bridge from that cost to a payoff.","Committees fund a solved problem, not a capability list."],"focus":["structure","precision"]},
    {"id":"narrative-sales-senior-12","level":"senior","profession":"sales","title":"The comp-change story for the field","scenario":"You're raising the accelerator threshold, which reps will resent. Framed as a takeaway, it demoralizes. Framed as a story — why the old plan misfired, how the new one rewards the right behavior — it can land.","task":"Write a 3-4 sentence framing that tells the story behind the comp change.","tips":["Explain the problem the old plan created — make it recognizable.","Cast the new plan as fixing that, in the rep's interest.","A story about fairness beats a memo about mechanics."],"focus":["structure","audience"]},
    {"id":"narrative-sales-senior-13","level":"senior","profession":"sales","title":"Pre-empting 'why not build it ourselves'","scenario":"A prospect's CTO is weighing buying from you versus building in-house. His strongest argument is control. Persuasion means raising the build option honestly and showing why buy wins for him.","task":"Write a 2-3 sentence passage that pre-empts the build argument fairly.","tips":["Concede what building gets him — control, fit.","Then show the true cost: time, maintenance, opportunity.","Fairly beating the build case is more convincing than ignoring it."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-14","level":"senior","profession":"sales","title":"The turnaround narrative for the board","scenario":"After a rough two quarters, you need the board to believe in the recovery. A list of fixes reads as scrambling. A narrative — what broke, what you changed, the leading indicators turning — reads as command.","task":"Write a 3-4 sentence turnaround narrative with a clear inflection point.","tips":["Name honestly what broke — credibility starts there.","Mark the inflection: what you changed and when.","Point to a leading indicator already moving — proof, not hope."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-15","level":"senior","profession":"sales","title":"Vivid stakes for the partner pitch","scenario":"You're pitching a hyperscaler on co-sell. 'It's a big opportunity' is abstract. Make the stakes concrete: the specific joint pipeline, the customer segment you'd win together that neither wins alone.","task":"Write a 2-3 sentence pitch that makes the joint opportunity concrete and mutual.","tips":["Size the joint pipeline with a real number.","Name the segment you win together but not apart.","Mutual, specific stakes beat generic 'strategic alignment.'"],"focus":["structure","precision"]},
    {"id":"narrative-sales-senior-16","level":"senior","profession":"sales","title":"The 'why now' for the GTM shift","scenario":"You're recommending a move upmarket and the exec team could see it as optional. Persuasion needs urgency: why this window, why waiting costs you, what a competitor does if you don't move.","task":"Write a 2-3 sentence passage that establishes why the shift must happen now.","tips":["Name the closing window — a market or competitive clock.","Quantify the cost of a year's delay.","'Why now' turns a good idea into a decision."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-17","level":"senior","profession":"sales","title":"The customer's board-ready story","scenario":"Your champion needs a story to sell the renewal to her own board. Features won't survive that room. Give her a before/after narrative in her board's language that she can tell as her own.","task":"Write a 3-4 sentence narrative she can tell her board about the partnership's impact.","tips":["Write it as her success story, not your product's.","Before and after in her board's metrics — cost, risk, growth.","She'll use it only if it makes her look good, not you."],"focus":["structure","audience"]},
    {"id":"narrative-sales-senior-18","level":"senior","profession":"sales","title":"Pre-empting the 'implementation risk' fear","scenario":"A large deal is stalling because the buyer fears a painful rollout. Ignoring the fear won't close it. Raise the implementation risk yourself and tell the story of how you de-risk it.","task":"Write a 2-3 sentence passage that names the rollout fear and answers it with a concrete plan.","tips":["Say the fear out loud — it shows you take it seriously.","Answer with a specific de-risking: phased rollout, dedicated team.","A named, answered fear closes deals; an ignored one kills them."],"focus":["structure","audience"]},
    {"id":"narrative-sales-senior-19","level":"senior","profession":"sales","title":"The win story for the company channel","scenario":"You're announcing the biggest deal in company history and your draft states the number. It inspires far more as a narrative: the underdog pursuit, the turning point, the close — briefly.","task":"Write a 3-4 sentence win narrative with a clear arc, ending on what it means for everyone.","tips":["A short arc — the hard middle, the turn, the close — sticks.","Keep it tight; the number is the climax, not a preamble.","End on what it proves the whole company can do."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-20","level":"senior","profession":"sales","title":"Making the miss a story of resolve","scenario":"You're explaining the missed quarter to the org and want them to come out motivated, not deflated. A narrative — what we learned, what we're changing, why we come back stronger — reframes the miss.","task":"Write a 3-4 sentence narrative that turns the miss into a forward story without spin.","tips":["Be honest about the miss — spin destroys the narrative.","Frame the learning as fuel, not as an excuse.","End on a concrete change, not a slogan."],"focus":["structure","audience"]},
    {"id":"narrative-sales-senior-21","level":"senior","profession":"sales","title":"Pre-empting the incumbent's advantage","scenario":"You're challenging an entrenched incumbent and the buyer's strongest reason to stay is switching cost. Persuasion means raising it, honoring it, and showing why the switch pays off anyway.","task":"Write a 2-3 sentence passage that acknowledges switching cost and overcomes it.","tips":["Concede switching is real work — don't pretend it's free.","Quantify the payoff that dwarfs the switching cost.","Show the migration path so the cost feels bounded."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-22","level":"senior","profession":"sales","title":"The vision that grounds the roadmap","scenario":"You're presenting the product roadmap to a strategic customer as a feature timeline. It persuades as a narrative: the future of their industry, the capabilities that future demands, how the roadmap gets them there.","task":"Write a 3-4 sentence narrative that frames the roadmap as a path to their future.","tips":["Open on their industry's trajectory, not your feature list.","Tie each roadmap beat to a capability that future needs.","Make them the protagonist arriving somewhere, not a recipient of features."],"focus":["structure","audience"]},
    {"id":"narrative-sales-senior-23","level":"senior","profession":"sales","title":"Concrete stakes for the budget-shift memo","scenario":"You're moving $2M from events to digital, and 'better ROI' is abstract. Make the stakes vivid: the pipeline the current spend fails to produce and the pipeline the shift unlocks, both in numbers.","task":"Write a 2-3 sentence passage that makes the cost of the status quo and the upside concrete.","tips":["Quantify what the current allocation is leaving on the table.","Make the upside specific and time-bound.","Two vivid numbers beat 'improved efficiency.'"],"focus":["structure","precision"]},
    {"id":"narrative-sales-senior-24","level":"senior","profession":"sales","title":"Pre-empting 'the market's just soft'","scenario":"You're pitching an investment in a new motion, and the easy objection is 'the whole market is down, why spend now.' Persuasion means raising that and showing why now is exactly the time to invest.","task":"Write a 2-3 sentence passage that pre-empts the 'wait for recovery' objection.","tips":["State the objection as the skeptic would.","Counter with why downturns are when share is won.","A specific counter-example or data point beats optimism."],"focus":["structure","impact"]},
    {"id":"narrative-sales-senior-25","level":"senior","profession":"sales","title":"The category-creation narrative","scenario":"You're positioning a new product line the market has no name for yet. Feature descriptions confuse buyers. A narrative — the problem no one had a category for, why it matters now, the new category you're naming — orients them.","task":"Write a 3-4 sentence narrative that frames the new category and why it exists now.","tips":["Start with the unnamed problem buyers already feel.","Explain why now — what makes the category necessary today.","Name the category clearly; ambiguity kills category creation."],"focus":["structure","clarity"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-sales-senior-01","level":"senior","profession":"sales","title":"The miss, told to the board","scenario":"You're opening the board update after an 8% miss. Your draft cushions it with three sentences of context first. Clear is kind: the board needs the bad news in the first line, then the plan.","task":"Write a 2-3 sentence opening that leads with the miss, then pivots to the plan.","tips":["Front-load the number — cushioning reads as spin to a board.","One sentence of cause, no litany.","Move to the plan quickly; that's what they can act on."],"focus":["clarity","impact"],"placeholder":"We closed at 92% of plan — an 8% miss. Here's what caused it and what we're changing."},
    {"id":"hard-sales-senior-02","level":"senior","profession":"sales","title":"The clean 'no' to the CEO's pet deal","scenario":"The CEO wants to pour resources into a logo you believe is a poor fit. Your draft is a maze of qualifications that never quite says no. Clear is kind: give a clean no with your reasoning.","task":"Write a 2-3 sentence response that says no clearly and gives the reason.","tips":["Say no in the first sentence — a buried no is a maybe.","One clear reason, not five hedges.","Respect the CEO enough to disagree plainly."],"focus":["clarity","impact"]},
    {"id":"hard-sales-senior-03","level":"senior","profession":"sales","title":"Behavior, impact, ask with a top rep","scenario":"Your best AE is sandbagging forecasts to protect his commit and it's distorting the roll-up. You need to address it. Vague 'be more accurate' won't land; behavior → impact → ask will.","task":"Write a 3-sentence message: the specific behavior, its impact, and the ask.","tips":["Name the behavior concretely — not 'accuracy,' but the sandbagging.","State the impact — on the forecast, on trust, on planning.","End with a clear, specific ask, not a vibe."],"focus":["clarity","precision"]},
    {"id":"hard-sales-senior-04","level":"senior","profession":"sales","title":"Telling the customer the date will slip","scenario":"You promised the customer's COO a go-live date you now know you'll miss by three weeks. Your draft buries it under progress updates. Clear is kind: tell her the slip up front, then the recovery plan.","task":"Write a 2-3 sentence message that leads with the slipped date and the new one.","tips":["Lead with the new date — she needs to replan around it.","Own the slip; don't dress it as 'refined timeline.'","Follow with what you're doing to hold the new date."],"focus":["clarity","impact"],"placeholder":"The go-live moves to March 21, three weeks later than planned. Here's why and how we hold it:"},
    {"id":"hard-sales-senior-05","level":"senior","profession":"sales","title":"The layoff message to the team","scenario":"You're announcing that the reorg eliminates six roles on the revenue team. Your draft leads with strategy and buries the cuts. The people affected deserve the hard news first, clearly and humanely.","task":"Write a 3-4 sentence opening that delivers the news directly and respectfully.","tips":["Say what's happening in the first two sentences — no strategy preamble.","Be direct and humane; vagueness is crueler than clarity.","State what comes next for those affected — support, timing."],"focus":["clarity","audience"]},
    {"id":"hard-sales-senior-06","level":"senior","profession":"sales","title":"Declining the customer's discount demand","scenario":"A major customer demands a 25% discount to renew. You're declining. Your draft over-apologizes and leaves room that invites more pressure. A clean, warm no holds the line and the relationship.","task":"Write a 2-3 sentence response that declines clearly while keeping it warm.","tips":["Decline plainly — a soft no gets tested harder.","Give one honest reason grounded in value, not policy alone.","Warmth in the close, firmness in the answer."],"focus":["clarity","audience"]},
    {"id":"hard-sales-senior-07","level":"senior","profession":"sales","title":"Telling the CEO a deal he championed is dead","scenario":"A deal the CEO personally worked just died. Your draft softens it with everything that 'could still happen.' Clear is kind: tell him it's dead, then what you learned.","task":"Write a 2-3 sentence message that states the deal is lost, then the takeaway.","tips":["Say it's over — false hope wastes his attention.","One honest reason it died.","Give the takeaway that makes the loss useful."],"focus":["clarity","impact"]},
    {"id":"hard-sales-senior-08","level":"senior","profession":"sales","title":"The performance conversation with a VP","scenario":"A regional VP who reports to you is missing on execution — pipeline discipline and rep coaching. Your draft is all encouragement and no substance. The feedback must name the gap clearly to be actionable.","task":"Write a 3-sentence message: the specific gap, its impact, and the expectation.","tips":["Name the execution gap concretely, with an example.","State the business impact — coverage, ramp, results.","Set a clear expectation, not a pep talk."],"focus":["clarity","precision"]},
    {"id":"hard-sales-senior-09","level":"senior","profession":"sales","title":"Saying no to the board's revenue ask","scenario":"The board pushes you to commit to a number you believe is unachievable. Your draft nods along vaguely. Clear is kind, and here it's also survival: say the number isn't credible and give the honest one.","task":"Write a 2-3 sentence response that declines the number and offers the defensible one.","tips":["Don't commit to a number you can't hit — the reckoning is worse.","State the credible number with the reasoning.","A hard no now beats a broken promise in 90 days."],"focus":["clarity","precision"]},
    {"id":"hard-sales-senior-10","level":"senior","profession":"sales","title":"Telling a partner the deal's off","scenario":"You're ending co-sell talks with a partner after months of work because the economics don't hold. Your draft drags it out. Clear is kind: tell them it's not proceeding and why, cleanly.","task":"Write a 2-3 sentence message that ends the talks respectfully and clearly.","tips":["State the decision plainly — don't leave a false door open.","Give the real reason: economics, fit, timing.","Respect the relationship for the future in the close."],"focus":["clarity","audience"]},
    {"id":"hard-sales-senior-11","level":"senior","profession":"sales","title":"The overrun the CFO must hear now","scenario":"Your team's sales-tooling spend is 30% over budget. Your draft buries it in a longer update. The CFO should hear the bad number first, plainly, with the cause and the correction.","task":"Write a 2-3 sentence message that leads with the overrun and the fix.","tips":["Lead with the number and the percentage over.","One clear cause — no diffusion across ten line items.","Come with the correction, not just the confession."],"focus":["clarity","precision"],"placeholder":"We're 30% over on sales tooling — about $240K. Here's the cause and how I'm bringing it back."},
    {"id":"hard-sales-senior-12","level":"senior","profession":"sales","title":"Delivering the demotion","scenario":"You're moving a manager back to an IC role because the team results demand it. Your draft is euphemistic to the point of confusion. Clear is kind: state the change directly and preserve their dignity.","task":"Write a 3-4 sentence message that delivers the change clearly and with respect.","tips":["Say what's changing plainly — euphemism confuses and insults.","Give the honest reason without piling on.","Affirm their value and the path forward."],"focus":["clarity","audience"]},
    {"id":"hard-sales-senior-13","level":"senior","profession":"sales","title":"Telling the customer their ask breaks the product","scenario":"A big customer demands a customization your team says will destabilize their instance. Your draft dances around it. Clear is kind: tell them plainly why you won't do it, and offer the real alternative.","task":"Write a 2-3 sentence response that declines the customization and offers a safe path.","tips":["Say no to the risky ask directly, with the reason.","Frame it as protecting them, not refusing them.","Offer the alternative that meets the underlying need."],"focus":["clarity","audience"]},
    {"id":"hard-sales-senior-14","level":"senior","profession":"sales","title":"The 'we're losing' update to the CEO","scenario":"You're behind in a competitive deal the CEO cares about, and your draft spins optimism. Clear is kind: tell him you're losing, why, and what would change it — so he can decide whether to engage.","task":"Write a 2-3 sentence message that states the honest position and the one lever.","tips":["Say you're behind — false optimism robs him of the choice to help.","Name the one factor deciding it.","Give the specific lever he could pull, if any."],"focus":["clarity","impact"]},
    {"id":"hard-sales-senior-15","level":"senior","profession":"sales","title":"Cutting a rep's territory","scenario":"You're pulling a major account from a rep's territory in the redesign, and it hurts their number. Your draft hides the impact. Clear is kind: tell them directly what they're losing and why, with the offset.","task":"Write a 3-sentence message: the specific change, the reason, and the offset.","tips":["Name exactly what's moving — don't let them discover it in a spreadsheet.","Give the honest rationale — coverage, fairness, focus.","State the offset so it's not pure loss."],"focus":["clarity","precision"]},
    {"id":"hard-sales-senior-16","level":"senior","profession":"sales","title":"The feedback to a peer exec","scenario":"Marketing's lead quality is hurting your team and you need to tell the CMO — a peer. Your draft either sugarcoats or accuses. Behavior → impact → ask keeps it constructive across the peer line.","task":"Write a 3-sentence message: the specific issue, its impact on revenue, and the ask.","tips":["Describe the specific lead-quality issue, not 'marketing is failing.'","Tie it to a revenue impact you can both see.","Ask for a specific joint fix, not a concession of fault."],"focus":["clarity","audience"]},
    {"id":"hard-sales-senior-17","level":"senior","profession":"sales","title":"Telling the board a key hire quit","scenario":"Your new CRO hire quit after 90 days and it's a real setback. Your draft buries it. The board needs the bad news directly, with your read on impact and your plan to cover.","task":"Write a 2-3 sentence update that states the departure, the impact, and your plan.","tips":["Say it plainly — the board will hear it regardless.","Give your honest read on the impact, sized.","Come with the interim plan, not just the news."],"focus":["clarity","impact"]},
    {"id":"hard-sales-senior-18","level":"senior","profession":"sales","title":"The clean 'no' to a feature promise","scenario":"A rep committed a roadmap feature to close a deal that engineering can't deliver. You have to tell the customer it's not coming. Clear is kind: say it won't ship, apologize once, and offer what's real.","task":"Write a 2-3 sentence message that retracts the promise honestly and offers a real path.","tips":["State plainly the feature isn't on the roadmap.","One clean apology for the miscommunication — not five.","Offer the workaround or timeline that is real."],"focus":["clarity","audience"]},
    {"id":"hard-sales-senior-19","level":"senior","profession":"sales","title":"Delivering the quota increase","scenario":"You're raising quotas 15% next year and the field will push back hard. Your draft hides the number in philosophy. Clear is kind: state the increase, the reason, and what support comes with it.","task":"Write a 3-sentence message: the increase, the rationale, and the support.","tips":["State the number and the effective date up front.","Give the honest business reason, not a motivational spin.","Pair the ask with the support — leads, enablement, headcount."],"focus":["clarity","audience"],"placeholder":"Quotas rise 15% next year. Here's the reason, and here's the support coming with it:"},
    {"id":"hard-sales-senior-20","level":"senior","profession":"sales","title":"Telling the customer you're deprecating a feature","scenario":"You're sunsetting a feature a key account depends on. Your draft frames it as an 'exciting evolution.' Clear is kind: tell them it's going away, when, and the migration path — no euphemism.","task":"Write a 2-3 sentence message that states the deprecation, the date, and the path.","tips":["Say the feature is being removed — 'evolution' insults them.","Give the hard date so they can plan.","Lead them to the migration path immediately."],"focus":["clarity","precision"]},
    {"id":"hard-sales-senior-21","level":"senior","profession":"sales","title":"The hard truth to an over-optimistic AE","scenario":"An AE keeps calling a deal 'basically closed' that you can see is stalled. You need to reset his read without crushing him. Behavior → impact → ask, delivered straight but supportively.","task":"Write a 3-sentence message: the pattern, its cost to the forecast, and what you need.","tips":["Name the pattern of optimism with a concrete instance.","Show the cost — a distorted forecast misleads everyone.","Ask for the specific evidence a 'closed' call requires."],"focus":["clarity","precision"]},
    {"id":"hard-sales-senior-22","level":"senior","profession":"sales","title":"Saying no to a channel partner's demand","scenario":"A reseller demands a bigger margin or threatens to drop your line. Your draft caves halfway. Clear is kind: decline the demand cleanly, restate the value of the partnership, and hold.","task":"Write a 2-3 sentence response that declines and reframes on partnership value.","tips":["Decline the margin demand plainly.","Reframe on the pipeline and support they get — the real value.","A half-cave invites the next demand; hold clean."],"focus":["clarity","impact"]},
    {"id":"hard-sales-senior-23","level":"senior","profession":"sales","title":"Telling the CEO you were wrong","scenario":"You pushed a GTM bet that isn't working and the CEO backed you on it. Clear is kind, including to yourself: tell him it isn't working, own the call, and bring the pivot.","task":"Write a 2-3 sentence message that owns the failed bet and proposes the pivot.","tips":["Say it isn't working — don't let him discover it.","Own the call as yours, not the market's.","Bring the pivot; ownership plus a next move is credibility."],"focus":["clarity","impact"]},
    {"id":"hard-sales-senior-24","level":"senior","profession":"sales","title":"The uncomfortable pricing truth to sales","scenario":"You're telling the field that deep discounting stops now, mid-year, which will make deals harder. Your draft over-explains. Clear is kind: state the new floor, the reason, and hold firm.","task":"Write a 3-sentence message: the new discount policy, the reason, and the expectation.","tips":["State the new floor and effective date plainly.","Give the margin reason honestly.","Set the expectation — sell value, not price — clearly."],"focus":["clarity","precision"]},
    {"id":"hard-sales-senior-25","level":"senior","profession":"sales","title":"Delivering the account loss to the exec team","scenario":"Your second-largest account is confirmed churning, $1.8M gone. Your draft opens with mitigation efforts. Clear is kind: state the loss and the number first, then what it means and what you're doing.","task":"Write a 2-3 sentence message that leads with the confirmed loss, then the response.","tips":["Lead with the loss and the ARR — no throat-clearing.","One honest sentence on cause.","Move to the containment and backfill plan."],"focus":["clarity","impact"],"placeholder":"Meridian is confirmed churning — $1.8M ARR gone at renewal. Here's the cause and our response:"}
  ],
  "putting-it-together": [
    {"id":"together-sales-senior-01","level":"senior","profession":"sales","title":"The full board revenue section","scenario":"You have five minutes and one slide for the revenue section of the board deck. You must land the result, the one risk, and one ask — led, structured, precise, and owned — with no room for warm-up.","task":"Write the complete 4-5 sentence board revenue section.","tips":["Lead with the number, structure into result/risk/ask.","Every claim carries a figure; own the recommendation.","Cut anything a director wouldn't act on."],"focus":["structure","impact"]},
    {"id":"together-sales-senior-02","level":"senior","profession":"sales","title":"The QBR opening that does everything","scenario":"You open a customer QBR with their C-suite. In three sentences you need to lead with their value delivered, in their language, precisely, and set up the arc — all before the first real slide.","task":"Write the complete 3-4 sentence QBR opening.","tips":["Lead with their outcome in their metric.","Signpost the three things you'll cover.","Precise, audience-first, and structured in one breath."],"focus":["audience","structure"]},
    {"id":"together-sales-senior-03","level":"senior","profession":"sales","title":"The cold email to a CEO","scenario":"You're writing a cold email to a target account's CEO. It must lead with the point, speak to her stake, be precise, and stay under 90 words — every principle at once, on a channel with zero patience.","task":"Write the complete cold email (under 90 words).","tips":["First line earns the second — her problem, your relevance.","One precise proof point, no feature list.","One clear ask; cut everything else."],"focus":["audience","concision"]},
    {"id":"together-sales-senior-04","level":"senior","profession":"sales","title":"The missed-quarter memo, whole","scenario":"Write the full missed-quarter memo to the exec team: lead with the miss, structure the cause and fix, be precise on numbers, own the controllable, and keep it to one screen. Everything, under real accountability.","task":"Write the complete memo (5-7 sentences).","tips":["Bad news first, plan fast, own the controllable.","Structure it: result, cause, fix — precise throughout.","Cut defense; length here reads as evasion."],"focus":["structure","clarity"]},
    {"id":"together-sales-senior-05","level":"senior","profession":"sales","title":"The negotiation counter to the CFO","scenario":"The customer's CFO countered your renewal with a 20% cut demand. Your reply must hold value, offer a real trade, stay warm, be precise on terms, and lead with your position — all in a few sentences under time pressure.","task":"Write the complete 3-4 sentence counter.","tips":["Lead with your position, then the specific trade.","Precise terms — numbers, not gestures.","Firm and warm; hold the line without breaking the room."],"focus":["impact","audience"]},
    {"id":"together-sales-senior-06","level":"senior","profession":"sales","title":"The 90-second CEO-staff update","scenario":"You have 90 seconds at the CEO's staff meeting. Cross-functional peers need the one conclusion that affects them, structured, precise, and pitched at their altitude — no funnel detail, no filler.","task":"Write the complete 90-second spoken update (4-5 sentences).","tips":["Lead with the cross-functional implication, not sales metrics.","Structure it and keep every number load-bearing.","Match altitude to a room of peers, not your own staff."],"focus":["audience","concision"]},
    {"id":"together-sales-senior-07","level":"senior","profession":"sales","title":"The RFP executive summary, complete","scenario":"Write the full executive summary for a competitive RFP: lead with why you win for them, mirror their criteria, be precise with proof, and stay under 150 words. The committee scores this page.","task":"Write the complete executive summary (under 150 words).","tips":["Open with their top requirement and your answer.","Structure by their scoring criteria, in their order.","Precise proof per criterion; cut boilerplate entirely."],"focus":["audience","structure"]},
    {"id":"together-sales-senior-08","level":"senior","profession":"sales","title":"The reorg announcement, all-in","scenario":"Write the complete territory-redesign announcement to 200 reps: lead with what changes and when, frame it as a better state, be precise on dates, and deliver the hard parts clearly. Everything, to an anxious audience.","task":"Write the complete announcement (5-7 sentences).","tips":["Lead with what changes for reps and the date.","Frame the why as their gain, not the org's.","Deliver the hard parts plainly; vagueness breeds rumor."],"focus":["audience","clarity"]},
    {"id":"together-sales-senior-09","level":"senior","profession":"sales","title":"The investor-day GTM segment","scenario":"Write your investor-day go-to-market segment: one governing claim, structured proof, precise economics, in investor language, delivered with presence — under a minute of speaking. The whole toolkit, on stage.","task":"Write the complete 5-6 sentence segment.","tips":["Governing claim first, three proof buckets under it.","Translate motion into economics investors model.","Own the claim; precise numbers, no operator jargon."],"focus":["structure","precision"]},
    {"id":"together-sales-senior-10","level":"senior","profession":"sales","title":"The big-deal review one-pager","scenario":"Write the full one-pager for the big-deal review with your sponsor: the deal, the plan to win, the risks, the ask — led, structured, precise, and owned. It must scan in a minute and drive a decision.","task":"Write the complete one-pager (5-7 sentences across the four sections).","tips":["Fixed sections: deal, plan, risks, ask.","Lead each with its point; precise dollars and dates.","Own the plan and the ask — no menu, a recommendation."],"focus":["structure","impact"]},
    {"id":"together-sales-senior-11","level":"senior","profession":"sales","title":"The kickoff keynote open","scenario":"Write your sales-kickoff keynote opening: lead with the year's one priority, frame a rallying before/after, keep it tight enough to remember, and own it. Three hundred sellers, one shot at the first minute.","task":"Write the complete 4-5 sentence keynote opening.","tips":["Priority in the first sentence — memorable, short.","A quick before/after that makes the priority feel winnable.","Own it in the first person; cut the thank-you preamble."],"focus":["impact","structure"]},
    {"id":"together-sales-senior-12","level":"senior","profession":"sales","title":"The escalation brief for the CEO","scenario":"A customer CIO is escalating to your CEO in an hour. Write the complete brief: what they want, our position, the recommended stance, and the one-line the CEO should hold — precise, structured, and ruthlessly short.","task":"Write the complete brief (4-5 sentences).","tips":["Lead with what the customer wants.","Structure: their want, our position, recommended stance.","Precise and short — he has minutes, not the file."],"focus":["structure","concision"]},
    {"id":"together-sales-senior-13","level":"senior","profession":"sales","title":"The pricing recommendation memo","scenario":"Write the full pricing-change memo to the exec team: lead with the recommendation, structure the case, back it with precise evidence, pre-empt the top objection, and own it. A real decision rests on this page.","task":"Write the complete memo (6-8 sentences).","tips":["Recommendation first, then the structured case.","Precise evidence — elasticity, benchmark, impact.","Pre-empt the churn objection; own the call."],"focus":["structure","precision"]},
    {"id":"together-sales-senior-14","level":"senior","profession":"sales","title":"The customer save email to their COO","scenario":"A key account is wavering and you're emailing their COO to save it. Lead with their realized value, address the specific friction, be precise, keep it warm, and make one clear ask — under 100 words.","task":"Write the complete email (under 100 words).","tips":["Lead with value in her KPI, then name the friction.","One precise proof point; one clear ask.","Warm, direct, and short — she reads for 30 seconds."],"focus":["audience","concision"]},
    {"id":"together-sales-senior-15","level":"senior","profession":"sales","title":"The board pipeline story","scenario":"Write the complete board pipeline narrative: SCQA framing, the one conclusion the numbers support, precise figures, and your recommended action — owned. Turn a table into an argument a director acts on.","task":"Write the complete 5-6 sentence pipeline narrative.","tips":["SCQA: situation, complication, question, answer.","One conclusion, precise coverage and concentration figures.","End on the owned recommendation, not the table."],"focus":["structure","impact"]},
    {"id":"together-sales-senior-16","level":"senior","profession":"sales","title":"The analyst briefing open","scenario":"Write your industry-analyst briefing opening: frame the market shift, place your company in it, be precise, and speak in patterns she can quote — with presence. The whole toolkit for a room that shapes perception.","task":"Write the complete 4-5 sentence briefing opening.","tips":["Open on the market movement, not your product.","Position your company as the shift's natural winner.","Precise, quotable, and confidently owned."],"focus":["audience","structure"]},
    {"id":"together-sales-senior-17","level":"senior","profession":"sales","title":"The comp-change note to managers","scenario":"Write the full comp-change note to sales managers: lead with the change and date, structure what to tell reps and what to escalate, be precise, and deliver the hard part cleanly. They cascade it within the hour.","task":"Write the complete note (5-6 sentences).","tips":["Change and date first; then rationale in one line.","Structure: what changed, what to tell reps, what to escalate.","Deliver the hard part plainly; arm them to answer reps."],"focus":["clarity","structure"]},
    {"id":"together-sales-senior-18","level":"senior","profession":"sales","title":"The win-announcement to the company","scenario":"Write the complete company-wide win announcement: lead with the logo and number, tell a tight arc, credit the team, and end on what it means — everything, in a message people actually finish.","task":"Write the complete announcement (4-5 sentences).","tips":["Logo and number first; the arc is the second beat.","Credit briefly and specifically.","End on what it proves the company can do."],"focus":["impact","structure"]},
    {"id":"together-sales-senior-19","level":"senior","profession":"sales","title":"The forecast-call script","scenario":"Write your complete weekly forecast update to the CEO and staff: company number, movers, risks, ask — led, structured, precise, and owned — in the fixed shape that trains the room. Delivered aloud, under two minutes.","task":"Write the complete 5-6 sentence forecast update.","tips":["Number first, then movers, risks, ask — same shape weekly.","Every figure precise; the swing deals named.","Own the call and the ask; no regional wandering."],"focus":["structure","precision"]},
    {"id":"together-sales-senior-20","level":"senior","profession":"sales","title":"The all-hands after the miss","scenario":"Write your complete all-hands remarks after a missed quarter: honest about the miss, structured on what changes, precise where it counts, pitched to employees' real fears, and steady throughout. The room's morale rides on it.","task":"Write the complete 6-8 sentence remarks.","tips":["Name the miss honestly; answer the job-security fear directly.","Structure: what happened, what changes, what stays.","Steady tone, precise where it reassures, forward-looking close."],"focus":["audience","clarity"]},
    {"id":"together-sales-senior-21","level":"senior","profession":"sales","title":"The partner co-sell proposal","scenario":"Write the complete co-sell proposal email to a hyperscaler's channel VP: lead with the mutual opportunity, size it precisely, pre-empt the channel-conflict fear, and make one clear ask — in their frame, under 120 words.","task":"Write the complete proposal email (under 120 words).","tips":["Lead with the joint opportunity and its size.","Pre-empt channel conflict with a concrete boundary.","One clear ask; precise and mutual throughout."],"focus":["audience","structure"]},
    {"id":"together-sales-senior-22","level":"senior","profession":"sales","title":"The GTM strategy recommendation","scenario":"Write the complete GTM strategy recommendation to the board: one governing bet, three supporting moves, precise economics, the top objection pre-empted, and your ownership of the call. The company's direction turns on it.","task":"Write the complete 7-9 sentence recommendation.","tips":["Governing bet first; three moves as structure.","Precise economics per move; pre-empt the strongest objection.","Own the recommendation — this is a decision, not a survey."],"focus":["structure","impact"]},
    {"id":"together-sales-senior-23","level":"senior","profession":"sales","title":"The renewal-risk brief to the CEO","scenario":"Write the complete renewal-risk brief to the CEO on your churning $1.8M account: lead with the risk and size, be precise on cause and probability, recommend the intervention you need from him, and own it — short enough to act on.","task":"Write the complete 4-5 sentence brief.","tips":["Lead with the account, dollars, and probability.","Precise on cause and trigger; separate fact from your read.","End with the specific ask of the CEO."],"focus":["precision","impact"]},
    {"id":"together-sales-senior-24","level":"senior","profession":"sales","title":"The quota-increase rollout","scenario":"Write the complete quota-increase message to the field: lead with the number and date, frame the why, pair it with support, deliver the hard part clearly, and keep it tight. It shapes a year of morale and effort.","task":"Write the complete 5-7 sentence rollout message.","tips":["Number and date first; honest reason, not a pep talk.","Pair the ask with concrete support.","Deliver plainly; respect the field's intelligence."],"focus":["clarity","audience"]},
    {"id":"together-sales-senior-25","level":"senior","profession":"sales","title":"The year-end board narrative","scenario":"Write the complete year-end revenue narrative for the board: the result, the honest complication, the strategic response, precise figures, and your ownership of the path forward. It sets the tone for next year's confidence in you.","task":"Write the complete 7-9 sentence narrative.","tips":["Win, but, so: result, honest complication, strategic response.","Precise figures throughout; separate fact from judgment.","Own the path forward — the board is grading your command."],"focus":["structure","impact"]}
  ]
};
